35: } 1: export function ScoreHistogram({ distribution }: { distribution: Array<{ bucket: string; count: number }> }) {
 2:   if (distribution.length === 0) return null;
 3: 
 4:   const maxCount = Math.max(...distribution.map((d) => d.count), 1);
 5: 
 6:   return (
 7:     <div>
 8:       <div className="histogram">
 9:         {distribution.map((d, i) => (
10:           <div
11:             key={i}
12:             className="histogram-bar"
13:             style={{ height: `${(d.count / maxCount) * 100}%` }}
14:             aria-label={`${d.bucket}: ${d.count} evaluations`}
15:           >
16:             <div className="tooltip">
17:               {d.bucket}: {d.count}
18:             </div>
19:           </div>
20:         ))}
21:       </div>
22:       <div className="histogram-labels">
23:         <span>{distribution[0]?.bucket}</span>
24:         <span>{distribution[distribution.length - 1]?.bucket}</span>
25:       </div>
26:     </div>
27:   );
28: } 1: import { memo } from 'react';
 2: 
 3: interface SparklineProps {
 4:   /** Array of score values (nulls allowed for gaps) */
 5:   data: (number | null)[];
 6:   /** SVG width in px */
 7:   width?: number;
 8:   /** SVG height in px */
 9:   height?: number;
10:   /** Stroke color (CSS var or hex) */
11:   color?: string;
12:   /** Accessible label for the sparkline */
13:   label?: string;
14: }
15: 
16: function SparklineInner({ data, width = 80, height = 24, color = 'var(--text-secondary)', label }: SparklineProps) {
17:   const values = data.filter((v): v is number => v !== null && Number.isFinite(v));
18:   if (values.length < 2) return null;
19: 
20:   const min = Math.min(...values);
21:   const max = Math.max(...values);
22:   const range = max - min || 1;
23:   const pad = 2;
24:   const xDenom = data.length > 1 ? data.length - 1 : 1;
25: 
26:   const points = data
27:     .map((v, i) => {
28:       if (v === null || !Number.isFinite(v)) return null;
29:       const x = pad + (i / xDenom) * (width - pad * 2);
30:       const y = pad + (1 - (v - min) / range) * (height - pad * 2);
31:       return `${x},${y}`;
32:     })
33:     .filter((p): p is string => p !== null)
34:     .join(' ');
35: 
36:   return (
37:     <svg
38:       width={width}
39:       height={height}
40:       viewBox={`0 0 ${width} ${height}`}
41:       role="img"
42:       aria-label={label ?? 'Score trend sparkline'}
43:       style={{ display: 'block' }}
44:     >
45:       <polyline
46:         points={points}
47:         fill="none"
48:         stroke={color}
49:         strokeWidth={1.5}
50:         strokeLinecap="round"
51:         strokeLinejoin="round"
52:       />
53:     </svg>
54:   );
55: }
