 24: 
 25: describe('scoreColorBand', () => {
 26:   describe('maximize direction (default)', () => {
 27:     it.each<[number, string]>([
 28:       [1.0, 'excellent'],
 29:       [0.95, 'excellent'],
 30:       [0.9, 'excellent'],   // >= 0.9 threshold
 31:       [0.89, 'good'],
 32:       [0.8, 'good'],        // >= 0.8 threshold
 33:       [0.79, 'adequate'],
 34:       [0.6, 'adequate'],    // >= 0.6 threshold
 35:       [0.59, 'poor'],
 36:       [0.4, 'poor'],        // >= 0.4 threshold
 37:       [0.39, 'failing'],
 38:       [0.0, 'failing'],
 39:     ])('score %f → %s', (score, expected) => {
 40:       expect(scoreColorBand(score, 'maximize')).toBe(expected);
 41:     });
 42:   });
 43: 
 44:   describe('minimize direction', () => {
 45:     it.each<[number, string]>([
 46:       [0.0, 'excellent'],   // 1 - 0.0 = 1.0 >= 0.9
 47:       [0.1, 'excellent'],   // 1 - 0.1 = 0.9 >= 0.9
