  5: 
  6: function SimpleAlertItem({ alert }: { alert: AlertWithMeta }) {
  7:   return (
  8:     <li className={`alert-item ${alert.severity}`}>
  9:       <div className="alert-message">{alert.message}</div>
 10:       <div className="alert-meta text-secondary text-xs">
 11:         {alert.aggregation} = {alert.actualValue?.toFixed(4)} (threshold: {alert.threshold?.toFixed(4)})
 12:       </div>
 13:       {alert.remediationHints && alert.remediationHints.length > 0 && (
 14:         <div className="remediation text-xs">
 15:           Hint: {alert.remediationHints[0]}
 16:         </div>
 17:       )}
 18:     </li>
 19:   );
 20: }
 21: 
 22: function ThresholdBar({ actual, threshold, direction }: {
 23:   actual: number;
 24:   threshold: number;
 25:   direction: 'above' | 'below';
 26: }) {
 27:   const max = Math.max(actual, threshold) * 1.2 || 1;
 28:   const actualPct = Math.max(0, Math.min((actual / max) * 100, 100));
 29:   const thresholdPct = Math.max(0, Math.min((threshold / max) * 100, 100));
 30:   const isViolating = direction === 'below' ? actual < threshold : actual > threshold;
 31: 
 32:   return (
 33:     <div className="threshold-bar" aria-label={`Actual: ${actual.toFixed(4)}, Threshold: ${threshold.toFixed(4)}`}>
 34:       <div
 35:         className="threshold-bar-fill"
 36:         style={{
 37:           width: `${actualPct}%`,
 38:           background: isViolating ? 'var(--status-critical)' : 'var(--status-healthy)',
 39:         }}
 40:       />
 41:       <div
 42:         className="threshold-bar-marker"
 43:         style={{ left: `${thresholdPct}%` }}
 44:         title={`Threshold: ${threshold.toFixed(4)}`}
 45:       />
 46:     </div>
 47:   );
 48: }
 49: 
 50: function CompoundAlertCard({ alert }: { alert: AlertWithMeta }) {
 51:   return (
 52:     <li className={`alert-item alert-compound ${alert.severity}`}>
 53:       <div className="alert-message">{alert.message}</div>
 54:       <div className="alert-meta text-secondary text-xs">
 55:         {alert.aggregation} = {alert.actualValue?.toFixed(4)} (threshold: {alert.threshold?.toFixed(4)})
 56:       </div>
 57: 
 58:       <ThresholdBar
 59:         actual={alert.actualValue}
 60:         threshold={alert.threshold}
 61:         direction={alert.direction}
 62:       />
 63: 
 64:       {alert.remediationHints && alert.remediationHints.length > 0 && (
 65:         <ol className="remediation-list text-xs">
 66:           {alert.remediationHints.map((hint, i) => (
 67:             <li key={i}>{hint}</li>
 68:           ))}
 69:         </ol>
 70:       )}
 71: 
 72:       {alert.relatedMetrics && alert.relatedMetrics.length > 0 && (
 73:         <div className="alert-related">
 74:           <span className="text-secondary text-xs">Related:</span>
 75:           {alert.relatedMetrics.map((m) => (
 76:             <Link key={m} href={`/metrics/${m}`} className="alert-metric-link text-xs">
 77:               {m}
 78:             </Link>
 79:           ))}
 80:         </div>
 81:       )}
 82:     </li>
 83:   );
 84: }
 85: 
 86: export function AlertList({ alerts }: { alerts: AlertWithMeta[] }) {
 87:   if (alerts.length === 0) return null;
 88: 
 89:   const sorted = [...alerts].sort((a, b) => {
 90:     const order = { critical: 0, warning: 1, info: 2 };
 91:     return (order[a.severity as keyof typeof order] ?? 2) - (order[b.severity as keyof typeof order] ?? 2);
 92:   });
 93: 
 94:   return (
 95:     <ul className="alert-list">
 96:       {sorted.map((alert, i) =>
 97:         alert.isCompound
 98:           ? <CompoundAlertCard key={`${alert.message}-${i}`} alert={alert} />
 99:           : <SimpleAlertItem key={`${alert.message}-${i}`} alert={alert} />
100:       )}
101:     </ul>
102:   );
