101:   }
102:   const sortByResult = SortBySchema.safeParse(c.req.query('sortBy'));
103:   if (!sortByResult.success) {
104:     return c.json({ error: 'Invalid sortBy. Must be score_asc, score_desc, or timestamp_desc.' }, HttpStatus.BadRequest);
105:   }
106:   const scoreLabelResult = ScoreLabelSchema.safeParse(c.req.query('scoreLabel') || undefined);
107:   if (!scoreLabelResult.success) {
