 32:   const band: ScoreColorBand = pct < 20 ? 'excellent' : pct < 50 ? 'adequate' : 'failing';
 33:   return (
 34:     <div className="variance-bar">
 35:       <BarIndicator value={pct} color={SCORE_COLORS[band]} style={{ flex: 1 }} />
 36:       <span className="mono-xs text-secondary" style={{ minWidth: 36 }}>
 37:         {value.toFixed(3)}
 38:       </span>
 39:     </div>
 40:   );
 41: }
