108:             }}
109:           >
110:             {shortName(rowMetric)}
111:           </div>
112: 
113:           {/* Data cells */}
114:           {metrics.map((colMetric, ci) => {
115:             const isDiag = ri === ci;
116:             const corr = isDiag ? undefined : lookupCorrelation(correlations, rowMetric, colMetric);
117:             const value = isDiag ? 1 : corr?.pearsonR ?? 0;
118:             const isToxic = corr?.isKnownToxicCombo ?? false;
119:             const bg = isDiag ? 'var(--bg-secondary, #2a2a2a)' : colorScale(value);
120: 
121:             const tooltip = isDiag
