 58: const STATUS_ICONS: Record<number, string> = {
 59:   0: '',      // UNSET
 60:   1: '\u2713', // OK ✓
 61:   2: '\u2717', // ERROR ✗
 62: };
 63: 
 64: function SpanRow({ node, depth, maxDuration }: { node: SpanNode; depth: number; maxDuration: number }) {
 65:   const barPct = maxDuration > 0 && node.durationMs ? Math.min((node.durationMs / maxDuration) * 100, 100) : 0;
 66:   const statusCode = node.status?.code ?? 0;
 67:   const isError = statusCode === 2;
 68: 
 69:   const barStyle: CSSProperties = {
 70:     height: 4,
 71:     width: `${barPct}%`,
 72:     background: isError ? 'var(--status-critical)' : 'var(--status-healthy)',
 73:     borderRadius: 2,
 74:     marginTop: 4,
 75:     minWidth: barPct > 0 ? 2 : 0,
 76:   };
 77: 
 78:   return (
 79:     <>
 80:       <div
 81:         className="flex-center gap-2 border-b"
 82:         style={{
 83:           paddingLeft: depth * 20 + 8,
 84:           paddingTop: 8,
 85:           paddingBottom: 8,
 86:         }}
 87:       >
 88:         <span className="text-base" style={{ color: isError ? 'var(--status-critical)' : 'var(--text-primary)' }}>
 89:           {STATUS_ICONS[statusCode]}
 90:         </span>
 91:         <div className="flex-1">
 92:           <div className="text-xs font-medium">{node.name}</div>
 93:           <div className="flex-center gap-2">
 94:             <div style={{ flex: 1, background: 'var(--bg-secondary)', borderRadius: 2, height: 4 }}>
 95:               <div style={barStyle} />
 96:             </div>
 97:             {node.durationMs != null && (
 98:               <span className="mono-xs text-secondary nowrap">
 99:                 {node.durationMs < 1000 ? `${node.durationMs.toFixed(0)}ms` : `${(node.durationMs / 1000).toFixed(2)}s`}
100:               </span>
101:             )}
102:           </div>
103:         </div>
104:         {node.evalCount > 0 && (
105:           <span className="text-2xs chip font-semibold" style={{
106:             background: 'var(--accent-bg)',
107:             color: 'var(--accent)',
108:           }}>
109:             {node.evalCount} eval{node.evalCount > 1 ? 's' : ''}
110:           </span>
111:         )}
112:       </div>
113:       {node.children.map(child => (
114:         <SpanRow key={child.spanId} node={child} depth={depth + 1} maxDuration={maxDuration} />
115:       ))}
116:     </>
117:   );
118: }
