 19: function CoverageGridInner({ metrics, inputs, cells, gaps, overallCoveragePercent }: CoverageGridProps) {
 20:   const [hovered, setHovered] = useState<{ metric: string; input: string } | null>(null);
 21: 
 22:   const cellMap = useMemo(() => {
