 36:   const displayInputs = inputs.slice(0, maxInputs);
 37:   const truncated = inputs.length > maxInputs;
 38: 
 39:   return (
 40:     <div role="region" aria-label="Evaluation coverage heatmap">
 41:       {/* Summary bar */}
 42:       <div className="flex-center mb-3 gap-3">
