 44:           {overallCoveragePercent.toFixed(1)}%
 45:         </span>
 46:         <span className="text-secondary text-base">
 47:           coverage ({metrics.length} metrics x {inputs.length} inputs)
 48:         </span>
 49:       </div>
 50: 
 51:       {/* Legend */}
 52:       <div className="mb-3 text-xs flex-wrap gap-4">
 53:         {(['covered', 'partial', 'missing'] as const).map(status => (
 54:           <div key={status} className="flex-center gap-1">
 55:             <div style={{
 56:               width: 12, height: 12, borderRadius: 2,
 57:               background: STATUS_COLORS[status],
 58:             }} />
 59:             <span>{status}</span>
 60:           </div>
 61:         ))}
 62:       </div>
 63: 
 64:       {/* Grid */}
 65:       <div className="overflow-x-auto">
 66:         <div
 67:           role="table"
 68:           aria-label="Coverage matrix"
 69:           className="gap-half"
 70:           style={{
 71:             display: 'grid',
 72:             gridTemplateColumns: `120px repeat(${displayInputs.length}, 28px)`,
 73:           }}
 74:         >
 75:           {/* Header row */}
 76:           <div role="row" className="contents">
 77:             <div role="columnheader" className="text-xs font-semibold" />
 78:             {displayInputs.map(input => (
 79:               <div
 80:                 key={input}
 81:                 role="columnheader"
 82:                 title={input}
 83:                 className="text-secondary text-2xs"
 84:                 style={{
 85:                   writingMode: 'vertical-lr',
 86:                   textAlign: 'end',
 87:                   overflow: 'hidden',
 88:                   maxHeight: 60,
 89:                 }}
 90:               >
 91:                 {truncateId(input, 8)}
 92:               </div>
 93:             ))}
 94:           </div>
 95: 
 96:           {/* Data rows */}
 97:           {metrics.map(metric => (
 98:             <div key={metric} role="row" className="contents">
 99:               <div
100:                 role="rowheader"
101:                 className="text-xs flex-center truncate font-medium"
102:                 title={metric}
103:               >
104:                 {metric}
105:               </div>
106:               {displayInputs.map(input => {
107:                 const cell = cellMap.get(`${metric}|${input}`);
108:                 const status = cell?.status ?? 'missing';
109:                 const count = cell?.count ?? 0;
110:                 const isHovered = hovered?.metric === metric && hovered?.input === input;
111: 
112:                 return (
113:                   <div
114:                     key={input}
115:                     role="cell"
116:                     aria-label={`${metric} / ${truncateId(input)}: ${status} (${count})`}
117:                     title={`${metric} / ${truncateId(input)}: ${count} evaluation${count !== 1 ? 's' : ''}`}
118:                     onMouseEnter={() => setHovered({ metric, input })}
119:                     onMouseLeave={() => setHovered(null)}
120:                     className="mono text-2xs"
121:                     style={{
122:                       width: 28,
123:                       height: 28,
124:                       borderRadius: 3,
125:                       background: STATUS_COLORS[status],
126:                       opacity: isHovered ? 1 : 0.8,
