128:                       display: 'flex',
129:                       alignItems: 'center',
130:                       justifyContent: 'center',
131:                       color: '#fff',
132:                       transition: 'opacity 0.15s',
133:                     }}
134:                   >
135:                     {count > 0 ? count : ''}
136:                   </div>
137:                 );
138:               })}
139:             </div>
140:           ))}
141:         </div>
142:       </div>
143: 
144:       {truncated && (
145:         <p className="text-secondary text-xs mt-2">
146:           Showing {maxInputs} of {inputs.length} inputs.
147:         </p>
148:       )}
149: 
150:       {/* Gap summary */}
