154:           <ul style={{ margin: 0, paddingLeft: 20, fontSize: 12 }}>
155:             {gaps.map(gap => (
156:               <li key={gap.metric} className="mb-1">
157:                 <strong>{gap.metric}</strong>: {gap.coveragePercent.toFixed(0)}% covered
158:                 ({gap.missingInputs.length} input{gap.missingInputs.length !== 1 ? 's' : ''} missing)
159:               </li>
160:             ))}
161:           </ul>
162:         </div>
163:       )}
164:     </div>
165:   );
166: }
