186: export function EvaluationTable({ evaluations }: { evaluations: EvalRow[] }) {
187:   const [sorting, setSorting] = useState<SortingState>([]);
188:   const [columnFilters, setColumnFilters] = useState<ColumnFiltersState>([]);
189:   const [activeCategories, setActiveCategories] = useState<LabelFilterCategory[]>([]);
190:   const [expanded, setExpanded] = useState<ExpandedState>({});
191: 
192:   const table = useReactTable({
193:     data: evaluations,
194:     columns,
195:     state: { sorting, columnFilters, expanded },
196:     onSortingChange: setSorting,
197:     onColumnFiltersChange: setColumnFilters,
198:     onExpandedChange: setExpanded,
199:     getRowCanExpand: () => true,
200:     getCoreRowModel: getCoreRowModel(),
201:     getSortedRowModel: getSortedRowModel(),
202:     getFilteredRowModel: getFilteredRowModel(),
203:     getExpandedRowModel: getExpandedRowModel(),
204:   });
205: 
206:   const toggleCategory = (cat: LabelFilterCategory) => {
207:     const next = activeCategories.includes(cat)
208:       ? activeCategories.filter((c) => c !== cat)
209:       : [...activeCategories, cat];
210:     setActiveCategories(next);
211:     setColumnFilters(
212:       next.length > 0 ? [{ id: 'label', value: next }] : [],
213:     );
214:   };
215: 
216:   const sortDir = (colId: string): 'ascending' | 'descending' | 'none' => {
217:     const s = sorting.find((entry) => entry.id === colId);
218:     if (!s) return 'none';
219:     return s.desc ? 'descending' : 'ascending';
220:   };
221: 
222:   return (
223:     <div>
224:       <div className="mb-3 gap-1-5" style={{ display: 'flex' }}>
225:         {(['Pass', 'Review', 'Fail'] as const).map((cat) => {
226:           const active = activeCategories.includes(cat);
227:           return (
228:             <button
229:               key={cat}
230:               type="button"
231:               onClick={() => toggleCategory(cat)}
232:               className="text-xs font-semibold cursor-pointer"
233:               style={{
234:                 padding: '4px 12px',
235:                 borderRadius: 6,
236:                 border: `1px solid ${CATEGORY_COLORS[cat]}`,
237:                 backgroundColor: active ? `${CATEGORY_COLORS[cat]}30` : 'transparent',
238:                 color: CATEGORY_COLORS[cat],
239:                 opacity: active ? 1 : 0.6,
240:                 transition: 'opacity 0.15s, background-color 0.15s',
241:               }}
242:             >
243:               {cat}
244:             </button>
245:           );
246:         })}
247:       </div>
248:       <table className="eval-table">
249:         <thead>
250:           {table.getHeaderGroups().map((hg) => (
251:             <tr key={hg.id}>
252:               {hg.headers.map((header) => {
253:                 const canSort = header.column.getCanSort();
254:                 return (
255:                   <th
256:                     key={header.id}
257:                     onClick={canSort ? header.column.getToggleSortingHandler() : undefined}
258:                     className="select-none"
259:                     style={{ cursor: canSort ? 'pointer' : 'default' }}
260:                     aria-sort={canSort ? sortDir(header.id) : undefined}
261:                   >
262:                     {flexRender(header.column.columnDef.header, header.getContext())}
263:                     {canSort && (
264:                       <span style={{ marginLeft: 4, fontSize: 'var(--font-size-2xs)' }}>
265:                         {{ asc: ' ^', desc: ' v' }[header.column.getIsSorted() as string] ?? ''}
266:                       </span>
267:                     )}
268:                   </th>
269:                 );
270:               })}
271:             </tr>
272:           ))}
273:         </thead>
274:         <tbody>
275:           {table.getRowModel().rows.map((row) => (
276:             <Fragment key={row.id}>
277:               <tr className={row.getIsExpanded() ? 'eval-row-expanded' : ''}>
278:                 {row.getVisibleCells().map((cell) => (
279:                   <td key={cell.id}>
280:                     {flexRender(cell.column.columnDef.cell, cell.getContext())}
281:                   </td>
282:                 ))}
283:               </tr>
284:               {row.getIsExpanded() && (
285:                 <tr className="eval-expanded-panel">
286:                   <td colSpan={row.getVisibleCells().length}>
287:                     <EvaluationExpandedRow row={row.original} />
288:                   </td>
289:                 </tr>
290:               )}
291:             </Fragment>
292:           ))}
293:           {table.getRowModel().rows.length === 0 && (
294:             <tr>
295:               <td colSpan={table.getVisibleLeafColumns().length} className="text-muted text-center p-4">
296:                 No evaluations match the current filter.
297:               </td>
298:             </tr>
299:           )}
300:         </tbody>
301:       </table>
302:     </div>
303:   );
