193: export function shortPath(fullPath: string): string {
194:   const parts = fullPath.replace(/\\/g, '/').split('/');
195:   return parts.length > 3 ? `\u2026/${parts.slice(-3).join('/')}` : fullPath;
196: }
197: 
198: export function fmtBytes(n: number): string {
199:   if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
200:   if (n >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
201:   return String(n);
202: }
203: 
204: // -- Timestamp formatting ---------------------------------------------------
205: 
206: export function formatTimestamp(ts: string): string {
207:   const d = new Date(ts);
208:   if (isNaN(d.getTime())) return ts || '-';
209:   const now = Date.now();
210:   const diffMs = now - d.getTime();
211:   const diffMin = Math.floor(diffMs / 60_000);
212:   if (diffMin < 1) return 'just now';
213:   if (diffMin < 60) return `${diffMin}m ago`;
214:   const diffHr = Math.floor(diffMin / 60);
215:   if (diffHr < 24) return `${diffHr}h ago`;
216:   const diffDay = Math.floor(diffHr / 24);
217:   if (diffDay < 7) return `${diffDay}d ago`;
218:   return d.toLocaleDateString();
