 42: function DashboardPage({ period }: { period: Period }) {
 43:   const { data, isLoading, isFetching, error } = useDashboard(period);
 44: 
 45:   if (isLoading && !data) return <MetricGridSkeleton />;
 46:   if (error && !data) return <div className="error-state"><h2>Failed to load</h2><p>{error.message}</p></div>;
 47: 
 48:   if (!data || ('role' in data)) return <MetricGridSkeleton />;
 49:   const dashboard = data;
 50:   const sparklines = (data as QualityDashboardSummary & { sparklines?: Record<string, (number | null)[]> }).sparklines;
 51: 
 52:   if (dashboard.overallStatus === 'no_data') {
 53:     return (
 54:       <div className="empty-state">
 55:         <h2>No Evaluation Data</h2>
 56:         <p>No evaluations found for the selected period.</p>
 57:         <p className="mt-2">
 58:           Run evaluations using the <code>obs_inject_evaluations</code> tool to see metrics here.
 59:         </p>
 60:       </div>
 61:     );
 62:   }
 63: 
 64:   return (
 65:     <>
 66:       {isFetching && data && <div className="refetch-indicator">Updating...</div>}
 67:       <HealthOverview dashboard={dashboard} />
 68:       <MetricGrid metrics={dashboard.metrics} sparklines={sparklines} />
 69:       {dashboard.alerts.length > 0 && (
 70:         <ViewSection title="Active Alerts">
 71:           <AlertList alerts={dashboard.alerts} />
 72:         </ViewSection>
 73:       )}
 74:       {dashboard.slaCompliance && dashboard.slaCompliance.length > 0 && (
 75:         <ViewSection title="SLA Compliance">
 76:           <SLATable slas={dashboard.slaCompliance} />
 77:         </ViewSection>
 78:       )}
 79:     </>
 80:   );
 81: }
