 83: function RolePage({ role, period }: { role: RoleViewType; period: Period }) {
 84:   const { data, isLoading, error } = useDashboard(period, role);
 85: 
 86:   if (isLoading && !data) return <MetricGridSkeleton />;
 87:   if (error && !data) return <div className="error-state"><h2>Failed to load</h2><p>{error.message}</p></div>;
 88:   if (!data || !('role' in data)) return <MetricGridSkeleton />;
 89: 
 90:   switch (data.role) {
 91:     case 'executive':
 92:       return <ExecutiveView data={data} />;
 93:     case 'operator':
 94:       return <OperatorView data={data} />;
 95:     case 'auditor':
 96:       return <AuditorView data={data} />;
 97:     default:
 98:       return null;
 99:   }
100: }
