102: function MetricDetailPage({ name, period }: { name: string; period: Period }) {
103:   const { data, isLoading, error } = useMetricDetail(name, period);
104:   const { data: trendData } = useTrend(name, period, 10);
105: 
106:   if (isLoading) {
107:     return (
108:       <div>
109:         <Link href="/" className="back-link">&larr; Back to dashboard</Link>
110:         <div className="card skeleton" style={{ height: 300 }} />
111:       </div>
112:     );
113:   }
114:   if (error) {
115:     return (
116:       <div>
117:         <Link href="/" className="back-link">&larr; Back to dashboard</Link>
118:         <div className="error-state"><h2>Failed to load</h2><p>{error.message}</p></div>
119:       </div>
120:     );
121:   }
122: 
123:   if (!data) return null;
124:   const detail = data;
125: 
126:   return (
127:     <div>
128:       <Link href="/" className="back-link">&larr; Back to dashboard</Link>
129:       <div className="card" style={{ marginBottom: 24 }}>
130:         <div className="metric-card-header">
131:           <h2 className="text-lg">{detail.displayName}</h2>
132:           <StatusBadge status={detail.status} />
133:         </div>
134:         <div className="gap-8 mt-3" style={{ display: 'flex', flexWrap: 'wrap' }}>
135:           {(['avg', 'min', 'max', 'p50', 'p95', 'p99'] as const).map((key) => {
136:             const val = detail.values[key];
137:             return (
138:               <div key={key} className="text-center">
139:                 <div className="mono-xl font-semibold">
140:                   {val !== null && val !== undefined ? val.toFixed(4) : 'N/A'}
141:                 </div>
142:                 <div className="text-secondary text-xs uppercase">{key}</div>
143:               </div>
144:             );
145:           })}
146:           <div className="text-center">
147:             <div className="mono-xl font-semibold">{detail.sampleCount}</div>
148:             <div className="text-secondary text-xs uppercase">samples</div>
149:           </div>
150:         </div>
151:         <div className="flex-center gap-4 mt-3">
152:           <TrendIndicator trend={detail.trend} />
153:           <ConfidenceBadge confidence={detail.confidence} />
154:         </div>
155:       </div>
156: 
157:       {detail.confidence && (
158:         <ViewSection title="Confidence Analysis">
159:           <div className="card">
160:             <ConfidencePanel confidence={detail.confidence} />
161:           </div>
162:         </ViewSection>
163:       )}
164: 
165:       <ViewSection title="Trend">
166:         <div className="card">
167:           <TrendChart
168:             trend={detail.trend}
169:             dynamics={(detail as MetricDetailResult & { dynamics?: MetricDynamics }).dynamics}
170:             warningThreshold={detail.alerts.find(a => a.severity === 'warning')?.threshold}
171:             criticalThreshold={detail.alerts.find(a => a.severity === 'critical')?.threshold}
172:             metricName={detail.displayName}
173:           />
174:         </div>
175:       </ViewSection>
176: 
177:       {trendData && trendData.trendData.length > 0 && (
178:         <ViewSection title={<>
179:           Time Series ({trendData.totalEvaluations} evaluations)
180:           {trendData.narrowed && (
181:             <span className="text-muted text-xs" style={{
182:               fontWeight: 400,
183:               marginLeft: 8,
184:             }}>auto-narrowed to data range</span>
185:           )}
186:         </>}>
187:           <div className="card">
188:             <TrendSeries data={trendData.trendData} metricName={detail.displayName} />
189:           </div>
190:         </ViewSection>
191:       )}
192: 
193:       {detail.alerts.length > 0 && (
194:         <ViewSection title="Alerts">
195:           <AlertList alerts={detail.alerts} />
196:         </ViewSection>
197:       )}
198: 
199:       <ViewSection title="Score Distribution">
200:         <div className="card">
201:           <ScoreHistogram distribution={detail.scoreDistribution} />
202:         </div>
203:       </ViewSection>
204: 
205:       <ViewSection title="Evaluations">
206:         <div className="card">
207:           <EvaluationDetail worst={detail.worstEvaluations} best={detail.bestEvaluations} metricName={name} period={period} />
208:         </div>
209:       </ViewSection>
210:     </div>
211:   );
212: }
