214: function RouteErrorFallback({ error, resetErrorBoundary }: { error: Error; resetErrorBoundary: () => void }) {
215:   return (
216:     <div className="error-state">
217:       <h2>Something went wrong</h2>
218:       <p>{error.message}</p>
219:       <div className="error-actions">
220:         <button onClick={resetErrorBoundary}>Try again</button>
221:         <Link href="/">Back to dashboard</Link>
222:       </div>
223:     </div>
224:   );
225: }
