227: function GlobalShortcuts({ setPeriod, navigate }: {
228:   setPeriod: (p: Period) => void;
229:   navigate: (path: string) => void;
230: }) {
231:   useShortcut('1', 'Switch to 24h', 'Period', useCallback(() => setPeriod('24h'), [setPeriod]));
232:   useShortcut('2', 'Switch to 7d', 'Period', useCallback(() => setPeriod('7d'), [setPeriod]));
233:   useShortcut('3', 'Switch to 30d', 'Period', useCallback(() => setPeriod('30d'), [setPeriod]));
234:   useShortcut('g h', 'Go to home', 'Navigation', useCallback(() => navigate('/'), [navigate]));
235:   useShortcut('g c', 'Go to correlations', 'Navigation', useCallback(() => navigate('/correlations'), [navigate]));
236:   useShortcut('g p', 'Go to pipeline', 'Navigation', useCallback(() => navigate('/pipeline'), [navigate]));
237:   useShortcut('g v', 'Go to coverage', 'Navigation', useCallback(() => navigate('/coverage'), [navigate]));
238:   useShortcut('g a', 'Go to agents', 'Navigation', useCallback(() => navigate('/agents'), [navigate]));
239:   return null;
240: }
