242: const BASE_PATH = import.meta.env.BASE_URL.replace(/\/$/, '') || '';
243: 
244: export function App() {
245:   const [period, setPeriod] = useState<Period>('30d');
246:   const [location, navigate] = useLocation();
247: 
248:   return (
249:     <Router base={BASE_PATH}>
250:     <KeyboardNavProvider>
251:     <RoleProvider>
252:     <GlobalShortcuts setPeriod={setPeriod} navigate={navigate} />
253:     <Layout period={period} onPeriodChange={setPeriod}>
254:       <RoleSelector />
255:       <Switch>
256:         <Route path="/">
257:           <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
258:             <DashboardPage period={period} />
259:           </ErrorBoundary>
260:         </Route>
261:         <Route path="/role/:roleName">
262:           {(params) => (
263:             <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
264:               <RolePage role={params.roleName as RoleViewType} period={period} />
265:             </ErrorBoundary>
266:           )}
267:         </Route>
268:         <Route path="/metrics/:metricName">
269:           {(params) => (
270:             <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
271:               <MetricDetailPage name={params.metricName} period={period} />
272:             </ErrorBoundary>
273:           )}
274:         </Route>
275:         <Route path="/evaluations/trace/:traceId">
276:           {(params) => (
277:             <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
278:               <EvaluationDetailPage traceId={params.traceId} />
279:             </ErrorBoundary>
280:           )}
281:         </Route>
282:         <Route path="/correlations">
283:           <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
284:             <CorrelationsPage period={period} />
285:           </ErrorBoundary>
286:         </Route>
287:         <Route path="/coverage">
288:           <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
289:             <CoveragePage period={period} />
290:           </ErrorBoundary>
291:         </Route>
292:         <Route path="/pipeline">
293:           <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
294:             <PipelinePage period={period} />
295:           </ErrorBoundary>
296:         </Route>
297:         <Route path="/compliance">
298:           <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
299:             <CompliancePage period={period} />
300:           </ErrorBoundary>
301:         </Route>
302:         <Route path="/agents">
303:           <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
304:             <AgentsPage period={period} />
305:           </ErrorBoundary>
306:         </Route>
307:         <Route path="/traces/:traceId">
308:           {(params) => (
309:             <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
310:               <TraceDetailPage traceId={params.traceId} />
311:             </ErrorBoundary>
312:           )}
313:         </Route>
314:         <Route path="/agents/:sessionId">
315:           {(params) => (
316:             <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
317:               <AgentSessionPage sessionId={params.sessionId} />
318:             </ErrorBoundary>
319:           )}
320:         </Route>
321:         <Route path="/sessions/:sessionId">
322:           {(params) => (
323:             <ErrorBoundary FallbackComponent={RouteErrorFallback} resetKeys={[location]}>
324:               <SessionDetailPage sessionId={params.sessionId} />
325:             </ErrorBoundary>
326:           )}
327:         </Route>
328:         <Route>
329:           <div className="empty-state">
330:             <h2>Page Not Found</h2>
331:             <p><Link href="/">Go to dashboard</Link></p>
332:           </div>
333:         </Route>
334:       </Switch>
335:     </Layout>
336:     </RoleProvider>
337:     </KeyboardNavProvider>
338:     </Router>
339:   );
340: }  1: import { Fragment, useCallback, useMemo, useState } from 'react';
  2: import { Link } from 'wouter';
  3: import type { AgentStat, EvalMetricSummary } from '../hooks/useAgentStats.js';
  4: import { scoreColorBand, SCORE_COLORS, truncateId, fmtBytes } from '../lib/quality-utils.js';
  5: import { AGENT_PALETTE, ERROR_RATE_WARNING_THRESHOLD } from '../lib/constants.js';
  6: import { BarIndicator } from './BarIndicator.js';
  7: import { Sparkline } from './Sparkline.js';
  8: 
  9: const COLUMN_COUNT = 7;
 10: const RATE_LIMIT_BADGE_BG = 'var(--bg-status-warning)';
 11: 
 12: type SortKey = 'invocations' | 'errorRate' | 'sessionCount' | 'avgOutputSize';
 13: 
 14: function errorRateColor(rate: number): string {
 15:   if (rate === 0) return 'var(--status-healthy)';
 16:   if (rate < ERROR_RATE_WARNING_THRESHOLD) return 'var(--status-warning)';
 17:   return 'var(--status-critical)';
 18: }
 19: 
 20: 
 21: interface AgentActivityPanelProps {
 22:   agents: AgentStat[];
 23: }
 24: 
 25: export function AgentActivityPanel({ agents }: AgentActivityPanelProps) {
 26:   const [sort, setSort] = useState<SortKey>('invocations');
 27:   const [asc, setAsc] = useState(false);
 28:   const [expanded, setExpanded] = useState<string | null>(null);
 29: 
 30:   const colorIndex = useMemo(
 31:     () => new Map(agents.map((a, i) => [a.agentName, AGENT_PALETTE[i % AGENT_PALETTE.length]])),
 32:     [agents],
 33:   );
 34: 
 35:   // React 18+ batches both setState calls in event handlers atomically
 36:   const toggleSort = useCallback((key: SortKey) => {
 37:     if (key === sort) {
 38:       setAsc(v => !v);
 39:     } else {
 40:       setSort(key);
 41:       setAsc(false);
 42:     }
 43:   }, [sort]);
 44: 
 45:   if (agents.length === 0) {
 46:     return (
 47:       <div className="text-muted text-center" style={{ padding: '32px 0' }}>
 48:         No agent activity recorded for this period.
 49:       </div>
 50:     );
 51:   }
 52: 
 53:   const maxInvocations = Math.max(...agents.map(a => a.invocations), 1);
 54: 
 55:   const sorted = [...agents].sort((a, b) => {
 56:     const diff = a[sort] < b[sort] ? -1 : a[sort] > b[sort] ? 1 : 0;
 57:     return asc ? diff : -diff;
 58:   });
 59: 
 60:   const sortIndicator = (key: SortKey) =>
 61:     sort === key ? (asc ? ' \u2191' : ' \u2193') : '';
 62: 
 63:   return (
 64:     <div className="overflow-x-auto">
 65:       <table className="sla-table" style={{ minWidth: 640 }}>
 66:         <thead>
 67:           <tr>
 68:             <th style={{ width: '30%' }}>Agent</th>
 69:             <th className="cursor-pointer select-none" onClick={() => toggleSort('invocations')}>
 70:               Invocations{sortIndicator('invocations')}
 71:             </th>
 72:             <th className="cursor-pointer select-none" onClick={() => toggleSort('errorRate')}>
 73:               Error Rate{sortIndicator('errorRate')}
 74:             </th>
 75:             <th className="cursor-pointer select-none" onClick={() => toggleSort('sessionCount')}>
 76:               Sessions{sortIndicator('sessionCount')}
 77:             </th>
 78:             <th className="cursor-pointer select-none" onClick={() => toggleSort('avgOutputSize')}>
 79:               Avg Output{sortIndicator('avgOutputSize')}
 80:             </th>
 81:             <th>Rate Limits</th>
 82:             <th>Source</th>
 83:           </tr>
 84:         </thead>
 85:         <tbody>
 86:           {sorted.map((agent) => {
 87:             const color = colorIndex.get(agent.agentName) ?? AGENT_PALETTE[0];
 88:             const errColor = errorRateColor(agent.errorRate);
 89:             const invPct = (agent.invocations / maxInvocations) * 100;
 90:             const topSource = Object.entries(agent.sourceTypes).sort((a, b) => b[1] - a[1])[0]?.[0];
 91:             const isExpanded = expanded === agent.agentName;
 92:             const hasLinks = agent.sessionIds.length > 0 || agent.traceIds.length > 0;
 93: 
 94:             return (
 95:               <Fragment key={agent.agentName}>
 96:                 <tr
 97:                   className={isExpanded ? 'eval-row-expanded' : ''}
 98:                   style={{ verticalAlign: 'middle', cursor: hasLinks ? 'pointer' : undefined }}
 99:                   onClick={() => hasLinks && setExpanded(isExpanded ? null : agent.agentName)}
100:                 >
101:                   {/* Agent name with color accent */}
102:                   <td>
103:                     <div className="flex-center gap-2">
104:                       {hasLinks && (
105:                         <span className="text-2xs text-muted shrink-0" style={{
106:                           transition: 'transform 0.15s',
107:                           transform: isExpanded ? 'rotate(90deg)' : 'none',
108:                         }}>
109:                           &#9654;
110:                         </span>
111:                       )}
112:                       <span className="shrink-0" style={{
113:                         display: 'inline-block',
114:                         width: 8,
115:                         height: 8,
116:                         borderRadius: '50%',
117:                         background: color,
118:                       }} />
119:                       <span className="mono-xs text-primary break-all">
120:                         {agent.agentName}
121:                       </span>
122:                     </div>
123:                   </td>
124: 
125:                   {/* Invocations with inline bar */}
126:                   <td>
127:                     <div className="flex-center gap-2">
128:                       <span className="mono-xs" style={{ minWidth: 32 }}>
129:                         {agent.invocations}
130:                       </span>
131:                       <BarIndicator value={invPct} color={color} opacity={0.7} style={{ flex: 1, minWidth: 48 }} />
132:                     </div>
133:                   </td>
134: 
135:                   {/* Error rate */}
136:                   <td>
137:                     <div className="flex-center gap-1-5">
138:                       <span className="mono-xs" style={{
139:                         color: errColor,
140:                       }}>
141:                         {agent.errors > 0 ? `${(agent.errorRate * 100).toFixed(1)}%` : '\u2014'}
142:                       </span>
143:                       {agent.errors > 0 && (
144:                         <span className="text-muted text-xs">
145:                           ({agent.errors})
146:                         </span>
147:                       )}
148:                     </div>
149:                   </td>
150: 
151:                   {/* Session count */}
152:                   <td>
153:                     <span className="mono-xs">
154:                       {agent.sessionCount}
155:                     </span>
156:                   </td>
157: 
158:                   {/* Avg output size */}
159:                   <td>
160:                     <span className="mono-xs text-secondary">
161:                       {fmtBytes(agent.avgOutputSize)}
162:                     </span>
163:                   </td>
164: 
165:                   {/* Rate limits */}
166:                   <td>
167:                     {agent.rateLimitCount > 0 ? (
168:                       <span className="mono-xs" style={{
169:                         color: 'var(--status-warning)',
170:                         background: RATE_LIMIT_BADGE_BG,
171:                         padding: '1px 6px',
172:                         borderRadius: 10,
173:                       }}>
174:                         {agent.rateLimitCount}x
175:                       </span>
176:                     ) : (
177:                       <span className="text-muted text-xs">{'\u2014'}</span>
178:                     )}
179:                   </td>
180: 
181:                   {/* Source type */}
182:                   <td>
183:                     {topSource ? (
184:                       <span className="mono text-muted text-2xs uppercase">
185:                         {topSource}
186:                       </span>
187:                     ) : <span className="text-muted">{'\u2014'}</span>}
188:                   </td>
189:                 </tr>
190: 
191:                 {/* Expanded row: eval summary + sessions + traces */}
192:                 {isExpanded && (
193:                   <tr className="eval-expanded-panel">
194:                     <td colSpan={COLUMN_COUNT} className="border-b" style={{ padding: '0 10px 10px' }}>
195:                       {/* Evaluation summary */}
196:                       <EvalSummaryRow evalSummary={agent.evalSummary} />
197: 
198:                       {/* Daily invocation sparkline */}
199:                       {agent.dailyCounts.length > 1 && agent.dailyCounts.some(v => v > 0) && (
200:                         <div className="border-b-subtle mb-1" style={{
201:                           padding: '10px 0 8px',
202:                         }}>
203:                           <div className="flex-center gap-3">
204:                             <div className="text-xs text-muted uppercase shrink-0">
205:                               Daily Activity
206:                             </div>
207:                             <Sparkline
208:                               data={agent.dailyCounts}
209:                               width={160}
210:                               height={28}
211:                               color={colorIndex.get(agent.agentName) ?? AGENT_PALETTE[0]}
212:                               label={`Daily invocations for ${agent.agentName}`}
213:                             />
214:                             <span className="mono text-muted text-2xs shrink-0">
215:                               peak {Math.max(...agent.dailyCounts)}/day
216:                             </span>
217:                           </div>
218:                         </div>
219:                       )}
220: 
221:                       <div className="gap-4" style={{
222:                         display: 'grid',
223:                         gridTemplateColumns: '1fr 1fr',
224:                         padding: '12px 0 4px',
225:                       }}>
226:                         {/* Sessions column */}
227:                         <div>
228:                           <div className="text-muted mb-1-5 text-xs uppercase">
229:                             Sessions ({agent.sessionCount})
230:                           </div>
231:                           <div className="flex-col gap-1">
232:                             {agent.sessionIds.map(sid => (
233:                               <Link
234:                                 key={sid}
235:                                 href={`/sessions/${sid}`}
236:                                 className="mono-xs link-accent"
237:                                 onClick={(e: React.MouseEvent) => e.stopPropagation()}
238:                               >
239:                                 {truncateId(sid, 12)}
240:                               </Link>
241:                             ))}
242:                             {agent.sessionIds.length === 0 && (
243:                               <span className="text-muted text-xs">none</span>
244:                             )}
245:                             {/* sessionCount === total unique sessions; sessionIds is capped at 50 */}
246:                             {agent.sessionIdsTruncated && (
247:                               <span className="text-muted text-2xs" style={{ fontStyle: 'italic' }}>
248:                                 +{agent.sessionCount - agent.sessionIds.length} more
249:                               </span>
250:                             )}
251:                           </div>
252:                         </div>
253: 
254:                         {/* Traces column */}
255:                         <div>
256:                           <div className="text-muted mb-1-5 text-xs uppercase">
257:                             Traces ({agent.traceIdsTotal ?? agent.traceIds.length})
258:                           </div>
259:                           <div className="flex-col gap-1">
260:                             {agent.traceIds.map(tid => (
261:                               <Link
262:                                 key={tid}
263:                                 href={`/traces/${tid}`}
264:                                 className="mono-xs link-accent"
265:                                 onClick={(e: React.MouseEvent) => e.stopPropagation()}
266:                               >
267:                                 {truncateId(tid, 12)}
268:                               </Link>
269:                             ))}
270:                             {agent.traceIds.length === 0 && (
271:                               <span className="text-muted text-xs">none</span>
272:                             )}
273:                             {agent.traceIdsTruncated && (
274:                               <span className="text-muted text-2xs" style={{ fontStyle: 'italic' }}>
275:                                 +{(agent.traceIdsTotal ?? 0) - agent.traceIds.length} more
276:                               </span>
277:                             )}
278:                           </div>
279:                         </div>
280:                       </div>
281:                     </td>
282:                   </tr>
283:                 )}
284:               </Fragment>
285:             );
286:           })}
287:         </tbody>
288:       </table>
289:     </div>
290:   );
291: }
292: 
293: /** Per-agent evaluation metrics (relevance, coherence, faithfulness, etc.) */
294: function EvalSummaryRow({ evalSummary }: { evalSummary: Record<string, EvalMetricSummary> }) {
295:   const metrics = Object.entries(evalSummary);
296:   if (metrics.length === 0) {
297:     return (
298:       <div className="text-xs text-muted border-b-subtle mb-1" style={{
299:         padding: '10px 0 4px',
300:       }}>
301:         No evaluations linked to this agent.
302:       </div>
303:     );
304:   }
305: 
306:   return (
307:     <div className="border-b-subtle mb-1" style={{
308:       padding: '10px 0 8px',
309:     }}>
310:       <div className="text-muted mb-1-5 text-xs uppercase">
311:         Evaluation Metrics
312:       </div>
313:       <div className="flex-wrap gap-3">
314:         {metrics.map(([name, m]) => {
315:           const band = scoreColorBand(m.avg);
316:           const barColor = SCORE_COLORS[band];
317:           return (
318:             <div key={name} style={{
319:               minWidth: 140,
320:               padding: '8px 10px',
321:               background: 'var(--bg-card)',
322:               border: '1px solid var(--border-subtle)',
323:               borderRadius: 'var(--radius)',
324:             }}>
325:               <div className="text-secondary mb-1 text-xs truncate">
326:                 {name}
327:               </div>
328:               {/* Score bar */}
329:               <div className="flex-center mb-1 gap-2">
330:                 <BarIndicator value={Math.min(m.avg * 100, 100)} color={barColor} style={{ flex: 1 }} />
331:                 <span className="mono-xs font-semibold text-right" style={{
332:                   color: barColor,
333:                   minWidth: 38,
334:                 }}>
335:                   {m.avg.toFixed(2)}
336:                 </span>
337:               </div>
338:               {/* Min/max range + count */}
339:               <div className="mono text-muted flex-wrap justify-between text-2xs">
340:                 <span>{m.min.toFixed(2)}\u2013{m.max.toFixed(2)}</span>
341:                 <span>n={m.count}</span>
342:               </div>
343:             </div>
344:           );
345:         })}
346:       </div>
347:     </div>
348:   );
349: }
