351: /** Summary bar above the table -- totals at a glance */
352: export function AgentActivitySummary({ agents }: AgentActivityPanelProps) {
353:   const totalInvocations = agents.reduce((s, a) => s + a.invocations, 0);
354:   const totalErrors = agents.reduce((s, a) => s + a.errors, 0);
355:   const totalRateLimits = agents.reduce((s, a) => s + a.rateLimitCount, 0);
356:   const overallErrorRate = totalInvocations > 0 ? (totalErrors / totalInvocations) * 100 : 0;
357: 
358:   return (
359:     <div style={{
360:       display: 'flex',
361:       gap: 'var(--space-8)',
362:       padding: 'var(--space-4) var(--space-5)',
363:       background: 'var(--bg-elevated)',
364:       borderRadius: 'var(--radius)',
365:       border: '1px solid var(--border-subtle)',
366:       marginBottom: 'var(--space-5)',
367:       flexWrap: 'wrap',
368:     }}>
369:       {[
370:         { label: 'Agents', value: agents.length },
371:         { label: 'Invocations', value: totalInvocations.toLocaleString() },
372:         {
373:           label: 'Error Rate',
374:           value: totalInvocations > 0 ? `${overallErrorRate.toFixed(1)}%` : '\u2014',
375:           color: overallErrorRate === 0
376:             ? 'var(--status-healthy)'
377:             : overallErrorRate < ERROR_RATE_WARNING_THRESHOLD * 100
378:               ? 'var(--status-warning)'
379:               : 'var(--status-critical)',
380:         },
381:         {
382:           label: 'Rate Limits',
383:           value: totalRateLimits > 0 ? totalRateLimits : '\u2014',
384:           color: totalRateLimits > 0 ? 'var(--status-warning)' : undefined,
385:         },
386:       ].map(({ label, value, color }) => (
387:         <div key={label} className="summary-count">
388:           <div className="value" style={color ? { color } : undefined}>{value}</div>
389:           <div className="label text-secondary text-xs">{label}</div>
390:         </div>
391:       ))}
392:     </div>
393:   );
394: }  1: import { type ReactNode } from 'react';
  2: import { Link } from 'wouter';
  3: import { useSessionDetail, SessionNotFoundError } from '../hooks/useSessionDetail.js';
  4: import { EvaluationTable, evalToRow, type EvalRow } from '../components/EvaluationTable.js';
  5: import { MonoTableHead } from '../components/MonoTableHead.js';
  6: import { ScoreBadge } from '../components/ScoreBadge.js';
  7: import { AgentScoreSummary } from '../components/AgentScoreSummary.js';
  8: import { PageShell } from '../components/PageShell.js';
  9: import { Section, type SectionHealth } from '../components/Section.js';
 10: import { SCORE_COLORS, scoreColorBand, shortPath, fmtBytes, truncateText, plural } from '../lib/quality-utils.js';
 11: import {
 12:   HALLUCINATION_SCORE_THRESHOLD,
 13:   MAX_ERROR_ROWS,
 14:   MAX_HALLUCINATION_ROWS,
 15:   MAX_FAILED_EVAL_ROWS,
 16:   SCORE_DISPLAY_PRECISION,
 17: } from '../lib/constants.js';
 18: import { BarIndicator } from '../components/BarIndicator.js';
 19: 
 20: // ─── Stat chip ───────────────────────────────────────────────────────────────
 21: 
 22: function Stat({ label, value, color }: { label: string; value: string | number; color?: string }) {
 23:   return (
 24:     <div className="text-center" style={{ flex: '1 1 100px', minWidth: 80 }}>
 25:       <div className="mono font-bold" style={{
 26:         fontSize: 22,
 27:         color: color ?? 'var(--text-primary)',
 28:         lineHeight: 1.1,
 29:       }}>{value}</div>
 30:       <div className="stat-label" style={{ letterSpacing: '0.1em', marginTop: 3 }}>{label}</div>
 31:     </div>
 32:   );
 33: }
 34: 
 35: // ─── Frequency bar ───────────────────────────────────────────────────────────
 36: 
 37: function FreqBar({ label, count, max, color }: { label: string; count: number; max: number; color?: string }) {
 38:   const pct = max > 0 ? (count / max) * 100 : 0;
 39:   return (
 40:     <div className="flex-center mb-1-5 gap-2-5">
 41:       <div className="mono-xs text-secondary text-right shrink-0 truncate" style={{
 42:         width: 160,
 43:       }}>{label}</div>
 44:       <BarIndicator
 45:         value={pct}
 46:         height={6}
 47:         color={color ?? 'var(--accent)'}
 48:         trackColor="var(--bg-elevated)"
 49:         style={{ flex: 1 }}
 50:       />
 51:       <div className="mono-xs text-muted text-right shrink-0" style={{
 52:         width: 36,
 53:       }}>{count}</div>
 54:     </div>
 55:   );
 56: }
 57: 
 58: // ─── Issue callout ───────────────────────────────────────────────────────────
 59: 
 60: function IssueCallout({ severity, title, children }: {
 61:   severity: 'warning' | 'critical';
 62:   title: string;
 63:   children: ReactNode;
 64: }) {
 65:   const color = severity === 'critical' ? 'var(--status-critical)' : 'var(--status-warning)';
 66:   return (
 67:     <div style={{
 68:       borderLeft: `3px solid ${color}`,
 69:       background: severity === 'critical' ? 'rgba(240,68,56,0.06)' : 'rgba(229,160,13,0.06)',
 70:       borderRadius: '0 var(--radius) var(--radius) 0',
 71:       padding: '10px 14px',
 72:       marginBottom: 10,
 73:     }}>
 74:       <div className="mono-xs uppercase font-semibold mb-1" style={{
 75:         color,
 76:       }}>{title}</div>
 77:       <div className="text-secondary text-xs leading-relaxed">
 78:         {children}
 79:       </div>
 80:     </div>
 81:   );
 82: }
 83: 
 84: 
 85: 
 86: function FreqBarGrid({ entries, max, color }: {
 87:   entries: [string, number][];
 88:   max: number;
 89:   color?: string;
 90: }) {
 91:   return (
 92:     <div className="freq-grid">
 93:       {[...entries]
 94:         .sort((a, b) => b[1] - a[1])
 95:         .map(([key, count]) => (
 96:           <FreqBar key={key} label={key} count={count} max={max} color={color} />
 97:         ))
 98:       }
 99:     </div>
100:   );
101: }
