103: // ─── Main page ───────────────────────────────────────────────────────────────
104: 
105: export function SessionDetailPage({ sessionId }: { sessionId: string }) {
106:   const { data, isLoading, error } = useSessionDetail(sessionId);
107:   const isNotSynced = !isLoading && error instanceof SessionNotFoundError;
108: 
109:   if (isLoading || (!isNotSynced && error)) {
110:     return <PageShell isLoading={isLoading} error={error ?? null} skeletonHeight={400}>{null}</PageShell>;
111:   }
112: 
113:   if (isNotSynced) {
114:     return (
115:       <div>
116:         <Link href="/" className="back-link">&larr; Back to dashboard</Link>
117:         <div className="card text-center" style={{ padding: '32px 24px' }}>
118:           <div className="mono-xs mb-1-5 uppercase text-warning">Session Not Yet Available</div>
119:           <div className="mono-xs text-secondary leading-relaxed" style={{
120:             maxWidth: 480,
121:             margin: '0 auto',
122:           }}>
123:             This session has not been synced to the dashboard KV store yet.
124:             Data is synced periodically &mdash; check back after the next pipeline run.
125:           </div>
126:           <div className="mono-xs text-muted mt-3 break-all">{sessionId}</div>
127:         </div>
128:       </div>
129:     );
130:   }
131: 
132:   if (!data) return null;
133: 
134:   const {
135:     dataSources, sessionInfo, toolUsage, mcpUsage,
136:     agentActivity, fileAccess, gitCommits, tokenProgression, spanBreakdown,
137:     alertSummary, codeStructure, errors,
138:     multiAgentEvaluation, evaluations,
139:   } = data;
140: 
141:   const si = sessionInfo ?? {
142:     projectName: 'unknown', workingDirectory: '', gitRepository: '', gitBranch: '',
143:     nodeVersion: '', resumeCount: 0, initialMessageCount: 0, initialContextTokens: 0,
144:     finalMessageCount: 0, taskCount: 0, uncommittedAtStart: 0,
145:   };
146:   const spanCount = dataSources.traces.count;
147:   const errorDetails = errors.details;
148: 
149:   // Derive computed values
150:   const totalToolCalls = Object.values(toolUsage).reduce((a, b) => a + b, 0);
151:   const totalMcpCalls = Object.values(mcpUsage).reduce((a, b) => a + b, 0);
152:   const maxTokenSnapshot = tokenProgression.at(-1);
153:   const maxToolCount = Math.max(...Object.values(toolUsage), 1);
154:   const maxMcpCount = Math.max(...Object.values(mcpUsage), 1);
155:   const maxFileCount = fileAccess[0]?.count ?? 1;
156:   const maxSpanCount = Math.max(...Object.values(spanBreakdown), 1);
157: 
158:   // Issue detection
159:   const hallucinationEvals = evaluations.filter(e =>
160:     (e.evaluationName ?? '').toLowerCase().includes('hallucin') ||
161:     ((e.scoreLabel ?? '').toLowerCase() === 'fail' && typeof e.scoreValue === 'number' && e.scoreValue < HALLUCINATION_SCORE_THRESHOLD)
162:   );
163:   const failedEvals = evaluations.filter(e =>
164:     (e.scoreLabel ?? '').toLowerCase() === 'fail'
165:   );
166:   const errorCount = errorDetails.length;
167:   const hasIssues = alertSummary.totalFired > 0 || errorCount > 0 ||
168:     hallucinationEvals.length > 0 || failedEvals.length > 0;
169:   const issueHealth: SectionHealth = errorCount > 0 || hallucinationEvals.length > 0
170:     ? 'crit'
171:     : alertSummary.totalFired > 0 || failedEvals.length > 0
172:     ? 'warn'
173:     : 'ok';
174: 
175:   // Score interpretation
176:   const evaluation = multiAgentEvaluation;
177:   const handoffScore = evaluation.handoffScore ?? 0;
178:   const avgRelevance = evaluation.avgTurnRelevance ?? 0;
179:   const completeness = evaluation.conversationCompleteness ?? 0;
180:   const evalRows: EvalRow[] = evaluations.map(evalToRow);
181: 
182:   // Unique models used
183:   const models = [...new Set(tokenProgression.map(t => t.model).filter(Boolean))];
184: 
185:   return (
186:     <div style={{ maxWidth: 1100 }}>
187:       <Link href="/" className="back-link">&larr; Back to dashboard</Link>
188: 
189:       {/* ── Header ── */}
190:       <div style={{
191:         background: 'var(--bg-card)',
192:         border: '1px solid var(--border-subtle)',
193:         borderBottom: 'none',
194:         padding: '20px 24px 16px',
195:         marginBottom: 0,
196:       }}>
197:         <div className="flex-wrap gap-4" style={{ alignItems: 'flex-start', justifyContent: 'space-between' }}>
198:           <div>
199:             <div className="mono text-muted mb-1-5 text-2xs uppercase">Session Detail</div>
200:             <div className="mono font-semibold text-base mb-2 break-all" style={{
201:               color: 'var(--accent-hover)',
202:               letterSpacing: '0.02em',
203:             }}>{sessionId}</div>
204:             <div className="text-secondary text-xs flex-wrap gap-4">
205:               <span>{si.projectName}</span>
206:               {si.gitRepository && (
207:                 <span className="text-muted">
208:                   {si.gitRepository}
209:                   {si.gitBranch ? ` · ${si.gitBranch}` : ''}
210:                 </span>
211:               )}
212:               {si.resumeCount > 1 && (
213:                 <span className="mono text-2xs chip uppercase" style={{
214:                   background: 'var(--accent-muted)',
215:                   color: 'var(--accent-hover)',
216:                 }}>RESUMED ×{si.resumeCount}</span>
217:               )}
218:               {models.map(m => (
219:                 <span key={m} className="mono text-2xs text-muted chip" style={{
220:                   background: 'var(--bg-elevated)',
221:                   border: '1px solid var(--border-subtle)',
222:                 }}>{m}</span>
223:               ))}
224:             </div>
225:           </div>
226:         </div>
227:       </div>
228: 
229:       {/* ── Vitals strip ── */}
230:       <div style={{
231:         display: 'flex',
232:         gap: 0,
233:         background: 'var(--bg-elevated)',
234:         border: '1px solid var(--border-subtle)',
235:         borderBottom: '1px solid var(--border)',
236:         padding: '14px 24px',
237:         flexWrap: 'wrap',
238:         rowGap: 12,
239:         marginBottom: 2,
240:       }}>
241:         <Stat label="Spans" value={spanCount} />
242:         <div className="vitals-divider" />
243:         <Stat label="Tool calls" value={totalToolCalls} />
244:         <div className="vitals-divider" />
245:         <Stat label="MCP calls" value={totalMcpCalls} />
246:         <div className="vitals-divider" />
247:         <Stat label="Commits" value={gitCommits.length} color={gitCommits.length > 0 ? 'var(--status-healthy)' : undefined} />
248:         <div className="vitals-divider" />
249:         <Stat label="Alerts fired" value={alertSummary.totalFired} color={alertSummary.totalFired > 0 ? 'var(--status-warning)' : undefined} />
250:         <div className="vitals-divider" />
251:         <Stat label="Errors" value={errorCount} color={errorCount > 0 ? 'var(--status-critical)' : undefined} />
252:         {maxTokenSnapshot && (
253:           <>
254:             <div className="vitals-divider" />
255:             <Stat label="Messages" value={maxTokenSnapshot.messages} />
256:             <div className="vitals-divider" />
257:             <Stat label="Output tokens" value={fmtBytes(maxTokenSnapshot.outputTokens)} />
258:           </>
259:         )}
260:       </div>
261: 
262:       {/* ── Issues & Anomalies ── */}
263:       <Section
264:         title="Issues & Anomalies"
265:         badge={hasIssues ? `${[
266:           alertSummary.totalFired > 0 && `${alertSummary.totalFired} alerts`,
267:           errorCount > 0 && `${errorCount} errors`,
268:           hallucinationEvals.length > 0 && `${hallucinationEvals.length} hallucinations`,
269:           failedEvals.length > 0 && `${failedEvals.length} failures`,
270:         ].filter(Boolean).join(' · ')}` : 'clean'}
271:         health={issueHealth}
272:         defaultOpen={hasIssues}
273:       >
274:         {!hasIssues && (
275:           <div className="mono-xs text-healthy">
276:             No issues detected in this session.
277:           </div>
278:         )}
279: 
280:         {alertSummary.totalFired > 0 && (
281:           <IssueCallout severity="warning" title={`${plural(alertSummary.totalFired, 'alert')} fired across ${plural(alertSummary.stopEvents, 'stop event')}`}>
282:             <strong>task-completion-low</strong> — The task completion ratio fell below 0.85.
283:             This fires when tasks are created but not marked complete before the session ends.
284:             Common causes: work deferred to backlog, sub-tasks spawned but not resolved,
285:             or tasks marked in-progress but not completed within the session.
286:           </IssueCallout>
287:         )}
288: 
289:         {errorCount > 0 && (
290:           <IssueCallout severity="critical" title={plural(errorCount, 'error span')}>
291:             <div className="mb-2">Tool invocations or agent calls that reported errors:</div>
292:             {errorDetails.slice(0, MAX_ERROR_ROWS).map((e, i) => (
293:               <div key={i} className="mono-xs mb-1">
294:                 <span style={{ color: 'var(--status-critical)' }}>✗</span>{' '}
295:                 {e.spanName}{e.tool ? ` (${e.tool})` : ''}{e.filePath ? ` · ${shortPath(e.filePath)}` : ''}
296:                 {e.errorType && e.errorType !== 'unknown' && <span className="text-muted"> — {e.errorType}</span>}
297:               </div>
298:             ))}
299:             {errorCount > MAX_ERROR_ROWS && (
300:               <div className="text-muted text-xs mt-1">
301:                 +{errorCount - MAX_ERROR_ROWS} more
302:               </div>
303:             )}
304:           </IssueCallout>
305:         )}
306: 
307:         {hallucinationEvals.length > 0 && (
308:           <IssueCallout severity="critical" title={`${plural(hallucinationEvals.length, 'hallucination indicator')} detected`}>
309:             <div className="mb-2">
