327: 
328:         {failedEvals.length > 0 && !hallucinationEvals.length && (
329:           <IssueCallout severity="warning" title={`${plural(failedEvals.length, 'evaluation')} marked fail`}>
330:             {failedEvals.slice(0, MAX_FAILED_EVAL_ROWS).map((e, i) => (
