332:                 <span className="text-warning">⚠</span>{' '}
333:                 {e.evaluationName} — score {typeof e.scoreValue === 'number' ? e.scoreValue.toFixed(SCORE_DISPLAY_PRECISION) : 'N/A'}
334:               </div>
335:             ))}
336:           </IssueCallout>
337:         )}
338: 
339:         {evaluation.errorPropagationTurns > 0 && (
340:           <IssueCallout severity="warning" title={plural(evaluation.errorPropagationTurns, 'error propagation turn')}>
341:             Errors detected in the multi-agent turn sequence may have propagated across agent handoffs.
342:           </IssueCallout>
343:         )}
344:       </Section>
345: 
346:       {/* ── Token Journey ── */}
347:       <Section
348:         title="Token Journey"
349:         badge={maxTokenSnapshot ? `${maxTokenSnapshot.messages} msg · ${fmtBytes(maxTokenSnapshot.outputTokens)} out` : 'no data'}
350:         health="neutral"
351:       >
352:         {tokenProgression.length === 0 ? (
353:           <div className="text-muted text-xs">No token snapshots recorded.</div>
354:         ) : (
355:           <div className="overflow-x-auto">
356:             <table className="mono-xs" style={{
357:               width: '100%', borderCollapse: 'collapse',
358:             }}>
359:               <MonoTableHead columns={[
360:                 { label: 'Messages' }, { label: 'Input' }, { label: 'Output' },
361:                 { label: 'Cache Read' }, { label: 'Cache Create' }, { label: 'Model' },
362:               ]} />
363:               <tbody>
364:                 {tokenProgression.map((t, i) => (
365:                   <tr key={i} className="border-b-subtle">
366:                     <td className="cell-pad-wide text-right">{t.messages}</td>
367:                     <td className="cell-pad-wide text-right text-secondary">{fmtBytes(t.inputTokens)}</td>
368:                     <td className="cell-pad-wide text-right" style={{ color: 'var(--accent-hover)' }}>{fmtBytes(t.outputTokens)}</td>
369:                     <td className="cell-pad-wide text-right text-muted">{fmtBytes(t.cacheRead)}</td>
370:                     <td className="cell-pad-wide text-right text-muted">{fmtBytes(t.cacheCreation)}</td>
371:                     <td className="cell-pad-wide text-right text-muted">{t.model}</td>
372:                   </tr>
373:                 ))}
374:               </tbody>
375:             </table>
376:           </div>
377:         )}
378:       </Section>
379: 
380:       {/* ── Tool Activity ── */}
381:       <Section
382:         title="Tool Activity"
383:         badge={`${totalToolCalls} calls · ${Object.keys(toolUsage).length} tools`}
384:         health="neutral"
385:       >
386:         <FreqBarGrid entries={Object.entries(toolUsage)} max={maxToolCount} />
387: 
388:         {totalMcpCalls > 0 && (
389:           <>
390:             <div className="stat-label" style={{ letterSpacing: '0.12em', margin: '14px 0 8px' }}>
391:               MCP Tools — {totalMcpCalls} calls
392:             </div>
393:             <FreqBarGrid entries={Object.entries(mcpUsage)} max={maxMcpCount} color="var(--status-healthy)" />
394:           </>
395:         )}
396:       </Section>
397: 
398:       {/* ── Agent Activity ── */}
399:       {agentActivity.length > 0 && (
400:         <Section
401:           title="Agent Activity"
402:           badge={agentActivity.map(a => `${a.agentName} ×${a.invocations}`).join(' · ')}
403:           health={agentActivity.some(a => a.errors > 0) ? 'warn' : 'neutral'}
404:         >
405:           <div className="gap-2-5" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))' }}>
406:             {agentActivity.map(a => (
407:               <div key={a.agentName} style={{
408:                 background: 'var(--bg-elevated)',
409:                 border: `1px solid ${a.errors > 0 ? 'var(--status-warning)' : 'var(--border-subtle)'}`,
410:                 borderRadius: 'var(--radius)',
411:                 padding: '10px 14px',
412:               }}>
413:                 <div className="mono-xs mb-1-5 font-semibold">
414:                   {a.agentName}
415:                 </div>
416:                 <div className="flex-wrap gap-3">
417:                   <div>
418:                     <div className="mono text-md font-bold">{a.invocations}</div>
419:                     <div className="stat-label">invocations</div>
420:                   </div>
421:                   {a.errors > 0 && (
422:                     <div>
423:                       <div className="mono text-md font-bold text-warning">{a.errors}</div>
424:                       <div className="stat-label">errors</div>
425:                     </div>
426:                   )}
427:                   <div>
428:                     <div className="mono text-md font-bold">{fmtBytes(a.avgOutputSize)}</div>
429:                     <div className="stat-label">avg output</div>
430:                   </div>
431:                 </div>
432:                 {a.hasRateLimit && (
433:                   <div className="mono mt-2 text-2xs text-warning">
434:                     ⚠ Hit rate limit
435:                   </div>
436:                 )}
437:               </div>
438:             ))}
439:           </div>
440: 
441:           {/* Multi-agent evaluation scores */}
442:           <div className="mt-4">
443:             <AgentScoreSummary handoffScore={handoffScore} avgRelevance={avgRelevance} completeness={completeness} />
444:           </div>
445:         </Section>
446:       )}
447: 
448:       {/* ── Files Accessed ── */}
449:       {fileAccess.length > 0 && (
450:         <Section
451:           title="Files Accessed"
452:           badge={`${fileAccess.length} files · top: ${shortPath(fileAccess[0]?.path ?? '')}`}
453:           health="neutral"
454:         >
455:           <div style={{ columns: '2 320px', columnGap: 32 }}>
456:             {fileAccess.map(({ path, count }) => (
457:               <div key={path} style={{ breakInside: 'avoid' }}>
458:                 <FreqBar
459:                   label={shortPath(path)}
460:                   count={count}
461:                   max={maxFileCount}
462:                   color="var(--accent)"
463:                 />
464:               </div>
465:             ))}
466:           </div>
467:         </Section>
468:       )}
469: 
470:       {/* ── Git Commits ── */}
471:       {gitCommits.length > 0 && (
472:         <Section
473:           title="Git Commits"
474:           badge={plural(gitCommits.length, 'commit')}
475:           health="ok"
476:         >
477:           <div className="flex-col gap-half">
478:             {gitCommits.map((commit, i) => {
479:               const commitFiles = commit.files?.split(' ') ?? [];
480:               return (
481:                 <details key={i} className="border-b-subtle">
482:                   <summary className="flex-center gap-2-5 cursor-pointer" style={{
483:                     padding: '8px 4px',
484:                     listStyle: 'none',
485:                   }}>
486:                     <span className="text-healthy text-2xs shrink-0">●</span>
487:                     <span className="mono-xs font-semibold flex-1">
488:                       {commit.subject}
489:                     </span>
490:                     {commitFiles.length > 0 && (
491:                       <span className="text-2xs text-muted shrink-0">
492:                         {plural(commitFiles.length, 'file')}
493:                       </span>
494:                     )}
495:                   </summary>
496:                   <div style={{ paddingLeft: 20, paddingBottom: 10 }}>
497:                     {commit.body && (
498:                       <div className="text-secondary text-xs leading-relaxed mb-2" style={{
499:                         fontFamily: 'var(--font-body)',
500:                       }}>
501:                         {commit.body}
502:                       </div>
503:                     )}
504:                     {commitFiles.length > 0 && (
505:                       <div className="mono text-2xs text-muted">
506:                         {commitFiles.map((f, fi) => (
507:                           <div key={fi}>{shortPath(f)}</div>
508:                         ))}
509:                       </div>
510:                     )}
511:                   </div>
512:                 </details>
513:               );
514:             })}
515:           </div>
516:         </Section>
517:       )}
518: 
519:       {/* ── Code Quality ── */}
520:       {codeStructure.length > 0 && (
521:         <Section
522:           title="Code Quality"
523:           badge={`${plural(codeStructure.length, 'file')} analyzed`}
524:           health={codeStructure.some(f => f.score < 0.6) ? 'warn' : 'ok'}
525:         >
526:           <div className="overflow-x-auto">
527:             <table className="mono-xs" style={{ width: '100%', borderCollapse: 'collapse' }}>
528:               <MonoTableHead columns={[
529:                 { label: 'File', align: 'left' }, { label: 'Tool', align: 'left' },
530:                 { label: 'Lines' }, { label: 'Exports' }, { label: 'Functions' },
531:                 { label: 'Types' }, { label: 'Score' },
532:               ]} />
533:               <tbody>
534:                 {codeStructure.map((f, i) => (
535:                   <tr key={i} className="border-b-subtle">
536:                     <td className="cell-pad text-secondary">{shortPath(f.file)}</td>
537:                     <td className="cell-pad text-muted">{f.tool}</td>
538:                     <td className="cell-pad text-right">{f.lines}</td>
539:                     <td className="cell-pad text-right text-muted">{f.exports}</td>
540:                     <td className="cell-pad text-right text-muted">{f.functions}</td>
541:                     <td className="cell-pad text-center">{f.hasTypes ? '✓' : '·'}</td>
542:                     <td className="cell-pad text-right font-semibold" style={{ color: SCORE_COLORS[scoreColorBand(f.score)] }}>
543:                       {f.score.toFixed(2)}
544:                     </td>
545:                   </tr>
546:                 ))}
547:               </tbody>
548:             </table>
549:           </div>
550:         </Section>
551:       )}
552: 
553:       {/* ── Span Breakdown ── */}
554:       <Section
555:         title="Span Breakdown"
556:         badge={`${spanCount} total · ${Object.keys(spanBreakdown).length} types`}
557:         health="neutral"
558:       >
559:         <FreqBarGrid entries={Object.entries(spanBreakdown)} max={maxSpanCount} color="var(--border-accent)" />
560:       </Section>
561: 
562:       {/* ── Evaluations ── */}
563:       <Section
564:         title="Evaluations"
565:         badge={evalRows.length > 0 ? plural(evalRows.length, 'result') : 'none'}
566:         health={hallucinationEvals.length > 0 ? 'crit' : failedEvals.length > 0 ? 'warn' : evalRows.length > 0 ? 'ok' : 'neutral'}
567:       >
568:         {evalRows.length === 0 ? (
569:           <div className="text-muted text-xs">
570:             No evaluations recorded for this session.
571:           </div>
572:         ) : (
573:           <EvaluationTable evaluations={evalRows} />
574:         )}
575:       </Section>
576:     </div>
577:   );
578: }  1: @import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600&family=IBM+Plex+Sans:wght@400;500;600&display=swap');
  2: 
  3: :root {
  4:   /* Backgrounds */
  5:   --bg-primary: #0a0e14;
  6:   --bg-card: #131920;
  7:   --bg-elevated: #1a2230;
  8:   --bg-surface: #1f2937;
  9:   --bg-hover: #243044;
 10: 
 11:   /* Borders */
 12:   --border: #2a3a4e;
 13:   --border-subtle: #1e2a3a;
 14:   --border-accent: #3b5278;
 15: 
 16:   /* Text */
 17:   --text-primary: #e2e8f0;
 18:   --text-secondary: #94a3b8;
 19:   --text-muted: #475569;
 20: 
 21:   /* Status */
 22:   --status-healthy: #26d97f;
 23:   --status-warning: #e5a00d;
 24:   --status-critical: #f04438;
 25:   --status-no-data: #6b7280;
 26: 
 27:   /* Accent */
 28:   --accent: #3b82f6;
 29:   --accent-hover: #60a5fa;
 30:   --accent-muted: #1e3a5f;
 31: 
 32:   /* Scores (alias shared values to status tokens) */
 33:   --score-excellent: var(--status-healthy);
 34:   --score-good: #34d399;
 35:   --score-adequate: var(--status-warning);
 36:   --score-poor: #f97316;
 37:   --score-failing: var(--status-critical);
 38: 
 39:   /* Typography */
 40:   --font-body: 'IBM Plex Sans', -apple-system, BlinkMacSystemFont, sans-serif;
 41:   --font-mono: 'JetBrains Mono', 'SF Mono', Consolas, monospace;
 42: 
 43:   /* Spacing */
 44:   --space-half: 2px;
 45:   --space-1: 4px;
 46:   --space-1-5: 6px;
 47:   --space-2: 8px;
 48:   --space-2-5: 10px;
 49:   --space-3: 12px;
 50:   --space-4: 16px;
 51:   --space-5: 20px;
 52:   --space-6: 24px;
 53:   --space-8: 32px;
 54:   --space-16: 64px;
 55: 
 56:   /* Layout */
 57:   --layout-max-width: 1280px;
 58: 
 59:   /* Status tints (bg + border pairs) */
 60:   --bg-status-healthy: #0d1f12;
 61:   --bg-status-warning: #1f1a0d;
 62:   --bg-status-critical: #1f0d0d;
 63:   --border-status-healthy: #1a3a1f;
 64:   --border-status-warning: #3a2f1a;
 65:   --border-status-critical: #3a1a1a;
 66: 
 67:   /* Accent alpha */
 68:   --accent-alpha-10: rgba(59, 130, 246, 0.1);
 69:   --accent-alpha-20: rgba(59, 130, 246, 0.2);
 70: 
 71:   /* Status glow alpha */
 72:   --healthy-alpha-15: rgba(38, 217, 127, 0.15);
 73:   --warning-alpha-15: rgba(229, 160, 13, 0.15);
 74:   --critical-alpha-20: rgba(240, 68, 56, 0.2);
 75:   --critical-alpha-40: rgba(240, 68, 56, 0.4);
 76:   --critical-alpha-60: rgba(240, 68, 56, 0.6);
 77: 
 78:   /* Radii */
 79:   --radius-xs: 2px;
 80:   --radius-bar: 3px;
 81:   --radius-sm: 4px;
 82:   --radius: 6px;
 83:   --radius-lg: 8px;
 84:   --radius-pill: 12px;
 85: 
 86:   /* Font sizes */
 87:   --font-size-2xs: 9px;
 88:   --font-size-xs: 12px;
 89:   --font-size-base: 14px;
 90:   --font-size-md: 16px;
 91:   --font-size-lg: 18px;
 92:   --font-size-xl: 20px;
 93:   --font-size-2xl: 24px;
 94: 
 95:   /* Label typography */
 96:   --label-letter-spacing: 0.5px;
 97: 
 98:   /* Transitions */
 99:   --transition-fast: 0.15s ease;
100:   --transition-bar: width 0.3s ease;
101: 
102:   /* Shadows */
103:   --shadow-sm: 0 1px 2px rgba(0,0,0,0.3);
104:   --shadow-glow-healthy: 0 0 12px var(--healthy-alpha-15);
105:   --shadow-glow-warning: 0 0 12px var(--warning-alpha-15);
106:   --shadow-glow-critical: 0 0 12px var(--critical-alpha-20);
107: }
108: 
109: * {
110:   margin: 0;
111:   padding: 0;
112:   box-sizing: border-box;
113: }
114: 
115: /* Shared uppercase label pattern */
116: .summary-count .label,
117: .sla-table th,
118: .section-label,
119: .cot-summary,
120: .agreement-grid .ag-header,
121: .stat-label,
122: .field-label {
123:   text-transform: uppercase;
124:   letter-spacing: var(--label-letter-spacing);
125: }
126: 
127: /* Shared accent link base + hover */
128: .back-link,
129: .tooltip-link,
130: .alert-metric-link {
131:   color: var(--accent);
132:   text-decoration: none;
133: }
134: .back-link:hover,
135: .tooltip-link:hover,
136: .alert-metric-link:hover {
137:   text-decoration: underline;
138: }
139: 
140: .sla-table th,
141: .eval-table th { font-size: var(--font-size-xs); }
142: 
143: .trend.stable { color: var(--text-secondary); }
144: 
145: /* Shared text truncation */
146: .eval-table .explanation,
147: .metric-worst {
148:   overflow: hidden;
149:   text-overflow: ellipsis;
150:   white-space: nowrap;
151: }
152: 
153: /* Shared flex row */
154: .health-banner,
155: .metric-card-header,
156: .metric-footer,
157: .header,
158: .pipeline-stat,
159: .confidence-header,
160: .variance-bar,
161: .eval-detail-meta,
162: .alert-related {
163:   display: flex;
164:   align-items: center;
165: }
166: 
167: /* Shared flex row (no align) */
168: .summary-counts,
169: .pipeline-stats {
170:   display: flex;
171:   gap: var(--space-6);
172: }
173: 
174: /* Shared inline-flex row */
175: .status-badge,
176: .trend,
177: .back-link,
178: .score-badge-wrapper {
179:   display: inline-flex;
180:   align-items: center;
181: }
182: 
183: body {
184:   font-family: var(--font-body);
185:   background: var(--bg-primary);
186:   color: var(--text-primary);
187:   line-height: 1.6;
188:   font-size: var(--font-size-base);
189:   -webkit-font-smoothing: antialiased;
190: }
191: 
192: @media (prefers-reduced-motion: reduce) {
193:   *, *::before, *::after {
194:     animation-duration: 0.01ms !important;
195:     transition-duration: 0.01ms !important;
196:   }
197: }
198: 
199: .dashboard-container {
200:   max-width: var(--layout-max-width);
201:   margin: 0 auto;
202:   padding: var(--space-6);
203: }
204: 
205: .metric-grid {
206:   display: grid;
207:   grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
208:   gap: var(--space-4);
209: }
210: 
211: .card {
212:   background: var(--bg-card);
213:   border: 1px solid var(--border-subtle);
214:   border-radius: var(--radius-lg);
215:   padding: var(--space-5);
216:   box-shadow: var(--shadow-sm);
217: }
218: 
219: .card:hover {
220:   border-color: var(--border);
221: }
222: 
223: .card.glow-warning { box-shadow: var(--shadow-glow-warning); }
224: .card.glow-critical { box-shadow: var(--shadow-glow-critical); }
225: 
226: .card-link {
227:   text-decoration: none;
228:   color: inherit;
229:   display: block;
230: }
231: 
232: /* Health banner */
233: .health-banner {
234:   padding: var(--space-4) var(--space-5);
235:   border-radius: var(--radius);
236:   margin-bottom: var(--space-6);
237:   justify-content: space-between;
238: }
239: .health-banner.healthy { background: var(--bg-status-healthy); border: 1px solid var(--border-status-healthy); }
240: .health-banner.warning { background: var(--bg-status-warning); border: 1px solid var(--border-status-warning); }
241: .health-banner.critical { background: var(--bg-status-critical); border: 1px solid var(--border-status-critical); }
242: .health-banner.no_data { background: var(--bg-card); border: 1px solid var(--border); }
243: 
244: .summary-count {
245:   text-align: center;
246: }
247: .summary-count .value {
248:   font-size: var(--font-size-2xl);
249:   font-weight: 600;
250:   font-family: var(--font-mono);
251: }
252: /* Status badges */
253: .status-badge {
254:   gap: var(--space-1-5);
255:   font-weight: 500;
256:   padding: var(--space-half) var(--space-2);
257:   border-radius: var(--radius-pill);
258: }
259: .status-badge.healthy { color: var(--status-healthy); background: var(--bg-status-healthy); }
260: .status-badge.warning { color: var(--status-warning); background: var(--bg-status-warning); }
261: .status-badge.critical { color: var(--status-critical); background: var(--bg-status-critical); }
262: .status-badge.no_data { color: var(--status-no-data); background: var(--bg-elevated); }
263: 
264: /* Trend indicator */
265: .trend {
266:   gap: var(--space-1);
267:   font-size: var(--font-size-xs);
268:   font-family: var(--font-mono);
269: }
270: .trend.improving { color: var(--status-healthy); }
271: .trend.degrading { color: var(--status-critical); }
272: /* Metric card */
273: .metric-card-header {
274:   justify-content: space-between;
275:   margin-bottom: var(--space-3);
276: }
277: .metric-card-header h3 {
278:   font-size: var(--font-size-base);
279:   font-weight: 500;
280: }
281: 
282: .metric-values {
283:   font-family: var(--font-mono);
284:   font-size: var(--font-size-xs);
285: }
286: .metric-values .primary {
287:   font-size: var(--font-size-2xl);
288:   font-weight: 600;
289:   line-height: 1.2;
290: }
291: .metric-values .secondary {
292:   color: var(--text-secondary);
293:   margin-top: var(--space-1);
294: }
295: 
296: /* Shared section divider */
297: .metric-footer,
298: .pipeline-stats,
299: .agreement-summary {
300:   margin-top: var(--space-3);
301:   padding-top: var(--space-3);
302:   border-top: 1px solid var(--border-subtle);
303:   font-size: var(--font-size-xs);
304:   color: var(--text-secondary);
305: }
306: 
307: .metric-footer {
308:   justify-content: space-between;
309:   border-top-color: var(--border);
310: }
311: 
312: /* Alerts */
313: .alert-list {
314:   list-style: none;
315: }
316: .alert-item {
317:   padding: var(--space-3) var(--space-4);
318:   border-left: 3px solid;
319:   background: var(--bg-card);
320:   margin-bottom: var(--space-2);
321:   border-radius: 0 var(--radius) var(--radius) 0;
322: }
323: .alert-item.critical { border-left-color: var(--status-critical); }
324: .alert-item.warning { border-left-color: var(--status-warning); }
325: .alert-item .alert-meta,
326: .alert-item .remediation {
327:   margin-top: var(--space-1);
328: }
329: .alert-item .remediation { color: var(--accent); }
330: 
331: /* Shared table cell borders */
332: .sla-table th,
333: .sla-table td,
334: .eval-table th,
335: .eval-table td,
336: .eval-table .eval-expanded-panel td {
337:   border-bottom: 1px solid var(--border);
338: }
339: 
340: /* Shared table header base */
341: .sla-table th,
342: .eval-table th {
343:   text-align: left;
344:   color: var(--text-secondary);
345:   font-weight: 500;
346: }
347: 
348: /* SLA table */
349: .sla-table {
350:   width: 100%;
351:   border-collapse: collapse;
352:   font-size: var(--font-size-base);
353: }
354: .sla-table th,
355: .sla-table td {
356:   padding: var(--space-2) var(--space-3);
357: }
358: 
359: /* Histogram */
360: .histogram {
361:   display: flex;
362:   align-items: flex-end;
363:   gap: var(--space-half);
364:   height: 120px;
365:   padding: var(--space-2) 0;
366: }
367: .histogram-bar {
368:   flex: 1;
369:   background: var(--accent);
370:   border-radius: var(--radius-xs) var(--radius-xs) 0 0;
371:   min-height: 2px;
372:   position: relative;
373: }
374: .histogram-bar:hover {
375:   opacity: 0.8;
376: }
377: /* Shared elevated surface */
378: .histogram-bar .tooltip,
379: .score-badge-tooltip,
380: .refetch-indicator {
381:   background: var(--bg-elevated);
382:   border: 1px solid var(--border);
383: }
384: 
385: /* Shared tooltip popup base */
386: .histogram-bar .tooltip,
387: .score-badge-tooltip {
388:   display: none;
389:   position: absolute;
390:   left: 50%;
391:   transform: translateX(-50%);
392: }
393: 
394: .histogram-bar .tooltip {
395:   bottom: 100%;
396:   padding: var(--space-1) var(--space-2);
397:   border-radius: var(--radius-sm);
398:   font-size: var(--font-size-xs);
399:   white-space: nowrap;
400:   z-index: 10;
401: }
402: .histogram-bar:hover .tooltip {
403:   display: block;
404: }
405: .histogram-labels {
406:   display: flex;
407:   justify-content: space-between;
408:   font-size: var(--font-size-xs);
409:   color: var(--text-muted);
410:   font-family: var(--font-mono);
411: }
412: 
413: /* Evaluation detail table */
414: .eval-table {
415:   width: 100%;
416:   border-collapse: collapse;
417:   font-size: var(--font-size-xs);
418: }
419: .eval-table th,
420: .eval-table td {
421:   padding: var(--space-1-5) var(--space-2-5);
422: }
423: .eval-table td {
424:   font-family: var(--font-mono);
425: }
426: .eval-table .explanation {
427:   font-family: inherit;
428:   color: var(--text-secondary);
429:   max-width: 300px;
430: }
431: .eval-table tbody tr:hover,
432: .eval-table .eval-row-expanded {
433:   background: var(--bg-elevated);
434: }
435: .eval-table .eval-expanded-panel td {
436:   padding: 0 var(--space-2-5) var(--space-2-5);
437: }
438: .eval-expanded-content {
439:   background: var(--bg-elevated);
440:   border-radius: var(--radius);
441:   padding: var(--space-4);
442:   animation: fade-in 0.15s ease-in-out;
443: }
444: 
445: /* Shared ghost button reset */
446: .tab-btn,
447: .period-btn {
448:   background: none;
449:   border: none;
450:   color: var(--text-secondary);
451:   cursor: pointer;
452: }
453: 
454: /* Tabs / Role selector */
455: .tab-nav {
456:   display: flex;
457:   gap: var(--space-1);
458:   margin-bottom: var(--space-6);
459:   border-bottom: 1px solid var(--border);
460:   padding-bottom: 0;
461: }
462: .tab-btn {
463:   padding: var(--space-2) var(--space-4);
464:   font-size: var(--font-size-base);
465:   border-bottom: 2px solid transparent;
466:   margin-bottom: -1px;
467:   transition: color var(--transition-fast), border-color var(--transition-fast);
468: }
469: .tab-btn:hover {
470:   color: var(--text-primary);
471: }
472: .tab-btn[aria-selected="true"] {
473:   color: var(--text-primary);
474:   border-bottom-color: var(--accent);
475: }
476: 
477: /* Period selector */
478: .period-selector {
479:   display: inline-flex;
480:   gap: var(--space-1);
481:   background: var(--bg-elevated);
482:   border-radius: var(--radius);
483:   padding: var(--space-half);
484: }
485: .period-btn {
486:   padding: var(--space-1) var(--space-3);
487:   border-radius: var(--radius);
488:   font-size: var(--font-size-xs);
489:   font-family: var(--font-body);
490: }
491: .period-btn.active {
492:   background: var(--bg-card);
493:   color: var(--text-primary);
494: }
495: 
496: /* Header */
497: .header {
498:   justify-content: space-between;
499:   margin-bottom: var(--space-6);
500: }
501: .header h1 {
502:   font-size: var(--font-size-xl);
503:   font-weight: 600;
504: }
505: 
506: /* Loading skeleton */
507: .skeleton {
508:   background: linear-gradient(90deg, var(--bg-card) 25%, var(--bg-elevated) 50%, var(--bg-card) 75%);
509:   background-size: 200% 100%;
510:   animation: skeleton-pulse 1.5s ease-in-out infinite;
511:   border-radius: var(--radius);
512: }
513: @keyframes skeleton-pulse {
514:   0% { background-position: 200% 0; }
515:   100% { background-position: -200% 0; }
516: }
517: 
518: /* Empty state */
519: .empty-state {
520:   text-align: center;
521:   padding: var(--space-16) var(--space-6);
522:   color: var(--text-secondary);
523: }
524: .empty-state h2 {
525:   color: var(--text-primary);
526:   margin-bottom: var(--space-2);
527: }
528: .empty-state code {
529:   background: var(--bg-elevated);
530:   padding: var(--space-half) var(--space-1-5);
531:   border-radius: var(--radius-sm);
532:   font-family: var(--font-mono);
533:   font-size: var(--font-size-xs);
534: }
535: 
536: /* Back link */
537: .back-link {
538:   font-size: var(--font-size-xs);
539:   gap: var(--space-1);
540:   margin-bottom: var(--space-4);
541: }
542: 
543: /* Error state */
544: .error-state {
545:   background: var(--bg-status-critical);
546:   border: 1px solid var(--border-status-critical);
547:   border-radius: var(--radius);
548:   padding: var(--space-6);
549:   text-align: center;
550: }
551: .error-state h2 {
552:   color: var(--status-critical);
553:   margin-bottom: var(--space-2);
554: }
555: .error-state .error-actions {
556:   display: flex;
557:   gap: var(--space-2);
558:   margin-top: var(--space-3);
559:   justify-content: center;
560: }
561: .error-state .error-actions button,
562: .error-state .error-actions a {
563:   padding: var(--space-1-5) var(--space-4);
564:   cursor: pointer;
565: }
566: 
567: /* Section headings */
568: .section-heading {
569:   font-size: var(--font-size-md);
570:   font-weight: 600;
571:   margin-bottom: var(--space-4);
572:   margin-top: var(--space-8);
573: }
574: 
575: /* Shared muted label */
576: .section-label,
577: .metric-worst,
578: .confidence-method {
579:   font-size: var(--font-size-xs);
580:   color: var(--text-muted);
581: }
582: 
583: /* Session detail — stat label, vitals divider, frequency grid */
584: .stat-label {
585:   font-size: var(--font-size-xs);
586:   font-family: var(--font-mono);
587:   color: var(--text-muted);
588: }
589: 
590: .vitals-divider {
591:   width: 1px;
592:   background: var(--border-subtle);
593:   margin: 0 var(--space-2);
594:   align-self: stretch;
595: }
596: 
597: .freq-grid {
598:   display: grid;
599:   grid-template-columns: repeat(auto-fill, minmax(340px, 1fr));
600:   gap: 0 var(--space-8);
601: }
602: 
603: /* View sections */
604: .view-section {
605:   margin-bottom: var(--space-8);
606: }
607: 
608: /* Refetch indicator */
609: .refetch-indicator {
610:   position: fixed;
611:   top: var(--space-4);
612:   right: var(--space-4);
613:   padding: var(--space-2) var(--space-4);
614:   border-radius: var(--radius);
615:   font-size: var(--font-size-xs);
616:   color: var(--text-secondary);
617:   z-index: 1000;
618:   animation: fade-in 0.2s ease-in-out;
619: }
620: 
621: @keyframes fade-in {
622:   from { opacity: 0; transform: translateY(-8px); }
623:   to { opacity: 1; transform: translateY(0); }
624: }
625: 
626: @keyframes toxicPulse {
627:   0%, 100% { box-shadow: 0 0 0 0 var(--critical-alpha-40); }
628:   50% { box-shadow: 0 0 6px 2px var(--critical-alpha-60); }
629: }
630: 
631: /* Score badge tooltip */
632: .score-badge-wrapper {
633:   position: relative;
634:   cursor: default;
635: }
636: .score-badge-tooltip {
637:   bottom: calc(100% + var(--space-2));
638:   border-radius: var(--radius);
639:   padding: var(--space-2-5) var(--space-3);
640:   min-width: 200px;
641:   max-width: 300px;
642:   z-index: 20;
643:   font-size: var(--font-size-xs);
644:   white-space: normal;
645:   animation: fade-in var(--transition-fast);
646: }
647: .score-badge-wrapper:hover .score-badge-tooltip,
648: .score-badge-wrapper:focus-within .score-badge-tooltip {
649:   display: block;
650: }
651: .tooltip-row {
652:   display: flex;
653:   justify-content: space-between;
654:   gap: var(--space-3);
655:   padding: var(--space-half) 0;
656:   color: var(--text-primary);
657: }
658: .tooltip-link {
659:   display: block;
660:   margin-top: var(--space-2);
661:   padding-top: var(--space-1-5);
662:   border-top: 1px solid var(--border);
663: }
664: 
665: /* Chain of thought panel */
666: .cot-panel {
667:   margin-top: var(--space-1);
668: }
669: .cot-summary {
670:   color: var(--text-secondary);
671:   cursor: pointer;
672:   padding: var(--space-1) 0;
673:   list-style: none;
674: }
675: .cot-summary::-webkit-details-marker {
676:   display: none;
677: }
678: .cot-summary::before {
679:   content: '\25B6';
680:   display: inline-block;
681:   margin-right: var(--space-1-5);
682:   font-size: var(--font-size-2xs);
683:   transition: transform var(--transition-fast);
684: }
685: details[open] > .cot-summary::before {
686:   transform: rotate(90deg);
687: }
688: .cot-content {
689:   font-size: var(--font-size-xs);
690:   color: var(--text-primary);
691:   line-height: 1.6;
692:   padding: var(--space-2) 0 var(--space-1);
693: }
694: 
695: /* Evaluation detail page */
696: .eval-detail-header {
697:   margin-bottom: var(--space-6);
698: }
699: .eval-detail-meta {
700:   gap: var(--space-4);
701:   margin-top: var(--space-2);
702: }
703: .eval-detail-card {
704:   margin-bottom: var(--space-4);
705: }
706: 
707: .eval-summary-card.card:hover {
708:   border-color: var(--accent);
709: }
710: 
711: /* Compound alert card */
712: .alert-compound {
713:   border-left-width: 4px;
714:   background: var(--bg-elevated);
715: }
716: .alert-related {
717:   flex-wrap: wrap;
718:   gap: var(--space-2);
719:   margin-top: var(--space-2);
720: }
721: .alert-metric-link {
722:   font-family: var(--font-mono);
723:   padding: var(--space-half) var(--space-2);
724:   border-radius: var(--radius-pill);
725:   background: var(--accent-alpha-10);
726: }
727: .alert-metric-link:hover {
728:   background: var(--accent-alpha-20);
729: }
730: .remediation-list {
731:   margin-top: var(--space-2);
732:   padding-left: var(--space-5);
733:   color: var(--accent);
734: }
735: .remediation-list li {
736:   margin-bottom: var(--space-1);
737: }
738: .threshold-bar {
739:   position: relative;
740:   height: 6px;
741:   background: var(--bg-card);
742:   border-radius: var(--radius-bar);
743:   margin-top: var(--space-2);
744:   overflow: visible;
745: }
746: /* Shared animated bar fill */
747: .threshold-bar-fill,
748: .variance-bar-fill {
749:   height: 100%;
750:   transition: var(--transition-bar);
751: }
752: .threshold-bar-fill { border-radius: var(--radius-bar); }
753: .variance-bar-fill  { border-radius: var(--radius-xs); }
754: .threshold-bar-marker {
755:   position: absolute;
756:   top: -3px;
757:   width: 2px;
758:   height: 12px;
759:   background: var(--text-primary);
760:   border-radius: calc(var(--radius-xs) / 2);
761:   transform: translateX(-1px);
762: }
763: 
764: /* Pipeline health stats in HealthOverview */
765: .pipeline-stat {
766:   gap: var(--space-1);
767: }
768: .pipeline-stat .stat-value {
769:   font-family: var(--font-mono);
770:   color: var(--text-primary);
771:   font-weight: 500;
772: }
773: 
774: /* Worst explanation preview on MetricCard */
775: .metric-worst {
776:   margin-top: var(--space-2);
777:   line-height: 1.4;
778: }
779: .metric-worst .worst-score {
780:   color: var(--score-failing);
781:   font-family: var(--font-mono);
782:   font-weight: 500;
783: }
784: 
785: /* Provenance panel */
786: .provenance-grid,
787: .agreement-grid {
788:   display: grid;
789:   gap: var(--space-1) var(--space-4);
790:   font-family: var(--font-mono);
791:   font-size: var(--font-size-xs);
792: }
793: .provenance-grid { grid-template-columns: auto 1fr; }
794: .provenance-grid .prov-label {
795:   color: var(--text-secondary);
796:   font-family: var(--font-body);
797:   white-space: nowrap;
798: }
799: .provenance-grid .prov-value {
800:   color: var(--text-primary);
801:   word-break: break-all;
802: }
803: .provenance-actions {
804:   display: flex;
805:   gap: var(--space-2);
806:   margin-top: var(--space-3);
807: }
808: .provenance-actions button {
809:   background: var(--bg-surface);
810:   border: 1px solid var(--border);
811:   color: var(--accent);
812:   padding: var(--space-1) var(--space-3);
813:   border-radius: var(--radius-sm);
814:   cursor: pointer;
815:   font-family: var(--font-body);
816: }
817: .provenance-actions button:hover {
818:   background: var(--bg-hover);
819:   border-color: var(--border-accent);
820: }
821: 
822: /* Confidence panel */
823: .confidence-header {
824:   gap: var(--space-2);
825:   margin-bottom: var(--space-3);
826: }
827: .confidence-method {
828:   font-family: var(--font-mono);
829: }
830: .agreement-grid { grid-template-columns: 1fr auto auto; }
831: .agreement-grid .ag-header {
832:   color: var(--text-muted);
833:   font-size: var(--font-size-xs);
834:   font-family: var(--font-body);
835:   padding-bottom: var(--space-1);
836:   border-bottom: 1px solid var(--border-subtle);
837: }
838: .agreement-summary .summary-value {
839:   font-family: var(--font-mono);
840:   color: var(--text-primary);
841: }
842: .variance-bar {
843:   gap: var(--space-2);
844: }
845: .variance-bar-track {
846:   flex: 1;
847:   height: 4px;
848:   background: var(--bg-surface);
849:   border-radius: var(--radius-xs);
850:   overflow: hidden;
851: }
852: 
853: /* Mini progress bar — track + fill */
854: .mini-bar {
855:   height: var(--bar-h, 4px);
856:   background: var(--bg-surface);
857:   border-radius: var(--radius-xs);
858:   overflow: hidden;
859: }
860: .mini-bar-fill {
861:   height: 100%;
862:   border-radius: var(--radius-xs);
863:   transition: var(--transition-bar);
864: }
865: 
866: /* Empty card state — card with muted placeholder text */
867: .card--empty {
868:   padding: var(--space-4);
869:   color: var(--text-muted);
870: }
871: 
872: /* Monospace utilities */
873: .mono      { font-family: var(--font-mono); }
874: .mono-xs   { font-family: var(--font-mono); font-size: var(--font-size-xs); }
875: .mono-xl   { font-family: var(--font-mono); font-size: var(--font-size-xl); }
876: 
877: /* Font size */
878: .text-2xs  { font-size: var(--font-size-2xs); }
879: .text-xs   { font-size: var(--font-size-xs); }
880: .text-base { font-size: var(--font-size-base); }
881: .text-md   { font-size: var(--font-size-md); }
882: .text-lg   { font-size: var(--font-size-lg); }
883: .text-xl   { font-size: var(--font-size-xl); }
884: .text-2xl  { font-size: var(--font-size-2xl); }
885: 
886: /* Text color utilities */
887: .text-secondary { color: var(--text-secondary); }
888: .text-muted     { color: var(--text-muted); }
889: 
890: /* Flex layout */
891: .flex-center { display: flex; align-items: center; }
892: 
893: /* Text transform */
894: .uppercase { text-transform: uppercase; letter-spacing: 0.05em; }
895: .tracking-wide { letter-spacing: 0.05em; }
896: .font-semibold { font-weight: 600; }
897: 
898: /* Chip / pill */
899: .chip { padding: 2px 6px; border-radius: 10px; }
900: 
901: /* Gap */
902: .gap-half { gap: var(--space-half); }   /*  2px */
903: .gap-1    { gap: var(--space-1); }      /*  4px */
904: .gap-1-5  { gap: var(--space-1-5); }    /*  6px */
905: .gap-2    { gap: var(--space-2); }      /*  8px */
906: .gap-2-5  { gap: var(--space-2-5); }    /* 10px */
907: .gap-3    { gap: var(--space-3); }      /* 12px */
908: .gap-4    { gap: var(--space-4); }      /* 16px */
909: .gap-6    { gap: var(--space-6); }      /* 24px */
910: .gap-8    { gap: var(--space-8); }      /* 32px */
911: 
912: /* Margin-bottom */
913: .mb-0   { margin-bottom: 0; }
914: .mb-1   { margin-bottom: var(--space-1); }
915: .mb-1-5 { margin-bottom: var(--space-1-5); }
916: .mb-2   { margin-bottom: var(--space-2); }     /*  8px */
917: .mb-3   { margin-bottom: var(--space-3); }
918: 
919: /* Margin-top */
920: .mt-1   { margin-top: var(--space-1); }     /*  4px */
921: .mt-2   { margin-top: var(--space-2); }     /*  8px */
922: .mt-3   { margin-top: var(--space-3); }     /* 12px */
923: .mt-4   { margin-top: var(--space-4); }     /* 16px */
924: 
925: /* Padding */
926: .p-4    { padding: var(--space-4); }        /* 16px */
927: 
928: /* Text align */
929: .text-center { text-align: center; }
930: .text-right  { text-align: right; }
931: .text-left   { text-align: left; }
932: 
933: /* Flex */
934: .flex-wrap          { display: flex; flex-wrap: wrap; }
935: .flex-col           { display: flex; flex-direction: column; }
936: .inline-flex-center { display: inline-flex; align-items: center; }
937: .shrink-0           { flex-shrink: 0; }
938: .flex-1             { flex: 1; }
939: .justify-between    { justify-content: space-between; }
940: .justify-center     { justify-content: center; }
941: 
942: /* Display */
943: .contents { display: contents; }
944: 
945: /* Typography */
946: .font-medium { font-weight: 500; }
947: .font-bold   { font-weight: 700; }
948: .nowrap      { white-space: nowrap; }
949: .truncate  { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
950: .break-all { word-break: break-all; }
951: .leading-relaxed { line-height: 1.6; }
952: 
953: /* Overflow */
954: .overflow-x-auto { overflow-x: auto; }
955: 
956: /* Interaction */
957: .select-none { user-select: none; }
958: 
959: /* Cursor */
960: .cursor-pointer { cursor: pointer; }
961: 
962: /* Status colors */
963: .text-healthy  { color: var(--status-healthy); }
964: .text-warning  { color: var(--status-warning); }
965: .text-critical { color: var(--status-critical); }
966: .text-primary  { color: var(--text-primary); }
967: 
968: /* Surface */
969: .surface-elevated { background: var(--bg-elevated); border: 1px solid var(--border); }
970: 
971: /* Link */
972: .link-accent { color: var(--accent); text-decoration: none; }
973: 
974: /* Table cells */
975: .cell-pad      { padding: 5px 10px; }
976: .cell-pad-wide { padding: 5px 12px; }
977: 
978: /* Border */
979: .border-b        { border-bottom: 1px solid var(--border); }
980: .border-b-subtle { border-bottom: 1px solid var(--border-subtle); }
